    ('era_judges', '언약궤 사건: 회개와 승리', '언약궤가 빼앗기는 아픔 뒤 블레셋 땅에서도 하나님의 권능이 드러나고, 백성은 회개하며 하나님은 천둥으로 구원을 보여주신다.', '["전투에서 이스라엘이 언약궤를 들고 나갔지만 블레셋에게 패배하고 군사들이 흩어지는 장면. 언약궤가 빼앗기는 위기가 보이되, 피와 시신은 보이지 않는다", "블레셋 다곤 신전 안에서 언약궤 앞에 다곤 신상이 넘어져 부서져 있고, 성읍 사람들은 몸을 움츠리며 괴로워한다. 종기의 고통은 표정과 자세로만 표현하고 피부 상처나 신체 훼손은 직접 보이지 않는다", "두 마리 소가 언약궤를 실은 새 수레를 끌고 블레셋 성읍을 떠나 이스라엘 쪽 벧세메스 길로 곧장 가는 장면. 블레셋 방백들은 멀리서 조심스럽게 지켜보고, 글자는 보이지 않는다", "블레셋 사람들이 이스라엘 백성을 치러 미스바로 올라오자, 하늘에서 하나님의 강한 천둥과 빛이 울려 블레셋 군대가 놀라 흩어지고 이스라엘이 승리하는 장면. 사무엘과 백성은 뒤쪽에서 하나님께 부르짖고 있으며, 피와 시신은 보이지 않는다"]'::jsonb, '[[], ["god"], [], ["samuel", "god"]]'::jsonb, ARRAY['samuel', 'god']::text[], '[{"book": "삼상", "from": "4:1", "to": "4:11"}, {"book": "삼상", "from": "5:1", "to": "6:21"}, {"book": "삼상", "from": "7:3", "to": "7:13"}]'::jsonb, -1075, -1075, 'approx', 13, 'lm_jud_mizpah', 'published'),
    ('era_exile_return', '에스라의 귀환: 말씀으로 정리하다', '에스라는 말씀의 사람으로 돌아와 공동체를 재정비한다.', '["에스라가 두루마리를 펼쳐 읽는다, 눈빛이 단단하다", "귀환 행렬이 길을 나선다, 먼지 나는 길 위의 결단", "예루살렘에 도착한 에스라가 현실을 보고 고개를 숙인다", "에스라가 율법을 연구하고 행하며 가르치기로 뜻을 정했다가 울린다"]'::jsonb, '[["ezra"], [], ["ezra"], ["ezra"]]'::jsonb, ARRAY['ezra']::text[], '[{"book": "스", "from": "7:1", "to": "7:10"}]'::jsonb, -458, -458, 'approx', 13, 'lm_exi_jerusalem', 'published'),
    ('era_divided_kingdom', '이사야의 소명: 거룩한 보좌의 환상', '이사야는 거룩하신 하나님의 보좌 환상 앞에서 자신의 죄를 깨닫고, 정결하게 된 뒤 보내심에 응답한다.', '["이사야의 큰 글자 없는 생각 풍선 안에 보이는 환상: 밝은 하나님의 보좌와 여섯 날개 스랍들 앞에서 두려워 떠는 이사야에게 한 스랍이 제단에서 가져온 핀 숯을 들고 날아와 이사야의 입술에 조심스럽게 대며 죄가 사해졌음을 상징한다. 숯은 작은 빛으로만 보이고 화상이나 상처는 보이지 않는다", "이사야의 큰 글자 없는 생각 풍선 안에 보이는 환상: 밝은 하나님의 보좌와 여섯 날개 스랍들 가운데서 하나님이 누구를 보낼지 부르시는 듯 빛이 퍼지고, 이사야는 두려움이 사라진 얼굴로 손을 들며 제가 여기 있으니 저를 보내 달라고 응답한다. 말풍선에는 글자가 없고, 손을 든 이사야와 보내심의 빛이 분명히 보인다", "이사야의 큰 글자 없는 생각 풍선 안에 보이는 환상: 하나님이 이사야에게 가서 전하라고 명하시며 밝은 빛이 이사야를 향해 뻗는다. 같은 생각 풍선 안쪽 먼 배경에는 사람들이 귀를 막고 눈을 감아 말씀을 듣지 않는 모습과, 성읍과 집들이 황폐해지는 장면이 상징적으로 보인다. 폭력이나 시신은 보이지 않고, 끝에는 잘린 나무 그루터기에서 작은 새싹이 남아 있는 모습이 희망의 표징처럼 보인다"]'::jsonb, '[["isaiah", "god"], ["isaiah", "god"], ["isaiah", "god"]]'::jsonb, ARRAY['isaiah', 'god']::text[], '[{"book": "사", "from": "6:1", "to": "6:13"}]'::jsonb, -740, -740, 'approx', 13, 'lm_div_jerusalem', 'published'),
    ('era_nt_apostolic', '1차 선교(4): 루스드라–더베', '루스드라와 더베에서 전도가 이어지지만, 폭력적 박해도 뒤따른다.', '["루스드라에서 걷지 못하던 사람이 바울의 말을 듣고 일어나자 무리가 크게 술렁인다", "사람들은 바울과 바나바를 신들로 여기며 제사를 드리려 하고, 두 사람은 급히 이를 말린다", "바울은 심한 박해를 겪고도 다시 일어선다", "일행은 더베로 가서 복음을 이어 전한다"]'::jsonb, '[["paul", "barnabas"], ["paul", "barnabas"], ["paul"], ["paul", "barnabas"]]'::jsonb, ARRAY['paul', 'barnabas']::text[], '[{"book": "행", "from": "14:8", "to": "14:20"}]'::jsonb, 47, 47, 'approx', 14, 'lm_nt_ap_lystra_derbe', 'published'),
    ('era_exodus', '금송아지: 아래에서 벌어진 일', '기다림을 견디지 못한 백성은 우상을 만들고 언약을 깨뜨린다.', '["백성이 아론을 둘러싼다", "금이 모이고 송아지 형상이 세워진다, 환호가 터진다", "산에서 내려오는 모세, 소리를 듣고 표정이 굳는다", "모세가 돌판을 던져 깨뜨린다, 진영이 얼어붙는다"]'::jsonb, '[["aaron"], [], ["moses"], ["moses"]]'::jsonb, ARRAY['moses', 'aaron']::text[], '[{"book": "출", "from": "32:1", "to": "32:35"}]'::jsonb, -1446, -1446, 'approx', 14, 'lm_exo_mt_sinai', 'published'),
    ('era_divided_kingdom', '아하스와 임마누엘: 믿음의 징조', '아하스는 두 왕의 위협 앞에서 흔들리지만, 하나님은 이사야를 통해 굳게 믿으라는 말씀과 임마누엘의 징조를 주신다.', '["아람 왕 르신의 군대와 북이스라엘 베가의 군대가 함께 예루살렘을 위협한다는 소식이 아하스 왕에게 전해지고, 아하스 왕과 백성의 마음이 숲이 바람에 흔들리듯 왕궁 안에서 두려워 떨고 있다", "아하스가 이사야 앞에서 망설이며 뒤로 물러나고, 손은 왕복을 붙잡고 눈치를 보며 하나님께 징조를 구하지 않겠다는 태도를 보인다. 뒤편에는 사람의 정치 계산과 군사 동맹을 상징하는 작은 지도와 병사 그림이 있고, 하늘의 빛은 외면당한다", "하나님의 빛이 이사야를 통해 아하스에게 임마누엘의 징조를 전한다. 큰 글자 없는 말풍선 안에는 젊은 여인이 아기를 안고 있고, 아기 곁에는 뻐터와 꿀, 악을 버리고 선을 택하는 두 길의 상징, 멀리 두 왕의 땅이 비어 가는 그림이 함께 보인다"]'::jsonb, '[["ahaz"], ["isaiah", "ahaz"], ["god", "isaiah", "ahaz"]]'::jsonb, ARRAY['isaiah', 'ahaz', 'god']::text[], '[{"book": "사", "from": "7:1", "to": "7:25"}]'::jsonb, -735, -735, 'approx', 14, 'lm_div_jerusalem', 'published'),
    ('era_monarchy', '언약궤 입성: 춤과 기쁨', '다윗은 언약궤가 들어올 때 온 마음으로 기뻐하며 예배한다.', '["언약궤를 실은 새 수레를 끄는 소들이 갑자기 뛰어 언약궤가 흔들리고, 웃사가 두 손을 뻗어 언약궤가 떨어지지 않게 붙잡으려는 장면. 웃사는 30대 이스라엘 남자, 베이지색 튜닉과 짙은 청록색 겉옷을 입은 같은 모습으로 보이며, 글자는 보이지 않는다", "웃사가 언약궤와 소들 곁에 쓰러져 움직이지 않고, 위에서는 하나님의 거룩한 진노를 상징하는 엄중한 금빛과 붉은 빛이 내려온다. 주변 사람들은 놀라 물러나고, 피와 상처와 시신의 세부 묘사는 보이지 않는다", "언약궤 앞에서 다윗이 멈추어 고개 숙인다", "언약궤가 예루살렘 성안으로 들어오자 다윗이 기뻐 힘을 다해 춤추며 겉옷이 벗겨지듯 흘러내리고 세마포 에봇 차림이 드러나는 장면. 노출이나 성적 묘사는 없고, 미갈은 궁 창가 멀리서 못마땅한 표정으로 다윗을 지켜본다"]'::jsonb, '[[], ["god"], ["david"], ["david"]]'::jsonb, ARRAY['david', 'god']::text[], '[{"book": "삼하", "from": "6:1", "to": "6:23"}]'::jsonb, -1000, -1000, 'approx', 14, 'lm_mon_jerusalem', 'published'),
    ('era_exile_return', '에스라의 회개와 정리: 거룩함을 회복하다', '에스라는 왕의 허락으로 예루살렘에 돌아오고, 백성의 죄 앞에서 회개하며 공동체를 말씀으로 정리한다.', '["에스라가 아닥사스다 왕의 칙서를 받고 기뻐하는 장면. 큰 글자 없는 말풍선 안에는 예루살렘으로 올라가려는 백성, 성전 기물, 금과 은, 밀, 포도주, 올리브 기름, 소금이 그림으로 담겨 있어 왕이 성전 회복을 허락한 내용이 분명히 보인다", "예루살렘 성전 안쪽 제단 앞에서 에스라가 사람들을 등지고 하나님을 향해 애통해하며 기도한다. 에스라는 찢어진 옷을 입고 무릎 꿇어 두 손을 하늘의 밝은 하나님의 빛을 향해 들고 있으며, 누구에게 빌거나 사과하는 모습이 아니다. 성전 바깥 먼 배경에는 이스라엘 남자들이 이방 여인들과 결혼해 우상 조각상과 작은 우상 제단을 곁에 두고 악한 생활을 하는 장면이 보인다. 그들은 화목한 가족처럼 보이지 않고, 이방 여인들은 작은 우상을 들고 차갑고 완강한 표정이며, 이스라엘 남자들은 죄를 깨닫지 못한 듯 고개를 돌리거나 머뭇거린다", "예루살렘 성전 앞 광장에서 에스라가 백성에게 죄를 자복하고 이방 여인들과 끊으라고 엄중히 명하는 장면. 이방 여인과 결혼했던 사람들이 슬픈 표정으로 가족들을 평화롭게 떠나보내며, 폭력이나 끌려가는 모습은 보이지 않는다"]'::jsonb, '[["ezra"], ["ezra"], ["ezra"]]'::jsonb, ARRAY['ezra']::text[], '[{"book": "스", "from": "7:11", "to": "7:22"}, {"book": "스", "from": "9:1", "to": "10:17"}]'::jsonb, -458, -458, 'approx', 14, 'lm_exi_jerusalem', 'published'),
    ('era_nt_public_ministry', '오병이어', '작은 나눔이 시작점이 되어 많은 사람이 먹고 남는다.', '["저녁이 가까워지자 제자들이 많은 무리의 먹을 것을 걱정한다", "한 아이가 떡 다섯 개와 물고기 두 마리를 내놓지만, 모두에게는 턱없이 적어 보인다", "예수는 무리를 앉게 하시고 떡과 물고기를 축사한 뒤 제자들을 통해 나누어 주신다", "모든 사람이 배불리 먹고도 열두 바구니가 남자, 제자들이 놀란다"]'::jsonb, '[["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus"], ["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "막", "from": "6:34", "to": "6:44"}, {"book": "마", "from": "14:13", "to": "14:21"}, {"book": "눅", "from": "9:10", "to": "9:17"}, {"book": "요", "from": "6:1", "to": "6:13"}]'::jsonb, 29, 29, 'approx', 14, 'lm_nt_pm_capernaum', 'published'),
    ('era_patriarch', '장자권: 한 그릇의 거래', '에서는 배고픔에 장자의 권리를 가볍게 팔고 야곱은 그것을 붙잡는다.', '["사냥에서 돌아온 에서가 지친 몸으로 장막으로 들어온다", "붉은 죽 냄새 앞에서 에서가 허기를 참지 못하고 야곱을 바라본다", "야곱이 장자권을 요구하고 에서가 망설인다", "에서가 허겁지겁 먹고, 뒤편에서는 야곱이 그 모습을 지켜본다"]'::jsonb, '[["esau"], ["esau", "jacob"], ["esau", "jacob"], ["esau", "jacob"]]'::jsonb, ARRAY['esau', 'jacob']::text[], '[{"book": "창", "from": "25:19", "to": "25:34"}]'::jsonb, -2006, -2006, 'approx', 14, 'lm_pat_beersheba', 'published'),
    ('era_nt_apostolic', '1차 선교(5): 안디옥(시리아)로 귀환 보고', '1차 여행을 마치고 돌아와 하나님이 하신 일을 교회에 보고한다.', '["바울과 바나바는 안디옥 교회로 돌아온다", "교회가 모이고 두 사람은 선교 이야기를 전한다", "이방인에게 믿음의 문이 열렸다는 소식이 퍼진다", "공동체는 하나님이 하신 일을 함께 기뻐한다"]'::jsonb, '[["paul", "barnabas"], ["paul", "barnabas"], ["paul", "barnabas"], []]'::jsonb, ARRAY['paul', 'barnabas']::text[], '[{"book": "행", "from": "14:21", "to": "14:28"}]'::jsonb, 48, 48, 'approx', 15, 'lm_nt_ap_antioch_syria', 'published'),
    ('era_exile_return', '느헤미야의 파송: 무너진 성벽 소식', '느헤미야는 예루살렘 소식을 듣고 눈물로 기도한 뒤 파송을 받는다.', '["느헤미야가 소식을 듣고 무너진 얼굴로 앉아 운다", "느헤미야가 밤의 기도, 주의 이름을 경외하는 종들을 기억하소서", "상대를 바라보며 기다린다, 느헤미야가 숨을 고른다", "왕의 허락과 편지가 주어진다, 느헤미야가 고개 숙여 감사한다"]'::jsonb, '[["nehemiah"], ["nehemiah"], ["nehemiah"], ["nehemiah"]]'::jsonb, ARRAY['nehemiah']::text[], '[{"book": "느", "from": "1:1", "to": "1:11"}, {"book": "느", "from": "2:1", "to": "2:8"}]'::jsonb, -445, -445, 'approx', 15, 'lm_exi_susa', 'published'),
    ('era_monarchy', '다윗 언약: 집을 세우리라', '하나님은 다윗에게 ‘네 집과 왕위를 견고케 하겠다’는 약속을 주신다.', '["으리으리한 백향목 궁전 안에서 다윗이 나단을 불러, 자신은 백향목 궁에 살지만 하나님의 언약궤는 장막 안에 있으니 하나님을 위한 집을 짓고 싶다고 제안하는 장면. 나단은 곁에서 진지하게 듣고, 궁전의 기둥과 백향목 장식이 분명히 보인다", "두 구역으로 나눈 장면: 한쪽에는 밤에 나단이 하나님의 음성을 듣고 경외하는 모습, 다른 한쪽에는 다음 날 나단이 다윗에게 와서 하나님이 다윗의 마음을 아시고 기뻐하시며, 성전은 후손이 짓고 하나님이 다윗의 집과 왕위를 세우시겠다는 약속을 전하는 모습. 하나님의 음성은 밝은 빛으로만 표현되고 글자는 보이지 않는다", "다윗이 성막 안으로 들어가 언약궤 가까이에 앉아 하나님께 감사 기도를 드리고, 주변에는 하나님의 부드러운 빛이 가득한 장면. 다윗은 겸손하게 고개를 숙이고, 왕관과 화려한 권위보다 감사와 경외가 강조된다"]'::jsonb, '[["david", "nathan"], ["god", "nathan", "david"], ["god", "david"]]'::jsonb, ARRAY['david', 'nathan', 'god']::text[], '[{"book": "삼하", "from": "7:1", "to": "7:17"}]'::jsonb, -995, -995, 'approx', 15, 'lm_mon_jerusalem', 'published')
)
insert into events (era_id, title, summary, story_scenes, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.story_scenes,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  story_scenes = excluded.story_scenes,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, story_scenes, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, landmark_code, status) as (
  values
    ('era_exodus', '모세의 중보: 다시 시작', '모세는 백성을 위해 중보하고 하나님은 관계 회복의 길을 여신다.', '["모세가 장막 밖에서 하나님께 간절한 얼굴로 기도하는 장면", "시내산에서 내려오는 모세의 양손에는 돌판 두개가 들려있고, 자기 얼굴에 광채가 나서 이스라엘 백성들은 눈을 가리고 쳐다볼 수가 없는 장면", "얼굴에 광채가 나는 모세가 얼굴을 수건으로 가리고 있는 모습", "하나님과 대화할때는 수건 없이 광채나는 얼굴로 하나님과 대화하는 모습"]'::jsonb, '[["god", "moses"], ["moses"], ["moses"], ["god", "moses"]]'::jsonb, ARRAY['moses', 'god']::text[], '[{"book": "출", "from": "33:7", "to": "34:35"}]'::jsonb, -1446, -1446, 'approx', 15, 'lm_exo_mt_sinai', 'published'),
    ('era_nt_public_ministry', '변화산', '예수님의 영광이 드러나고 제자들은 ‘그의 말을 들으라’는 음성을 듣는다.', '["예수와 세 제자가 산을 오르며 숨을 고른다", "예수의 모습이 빛나고, 모세와 엘리야가 함께 선다", "베드로가 결연한 표정으로 선다", "하늘에서 빛이 비치고, 제자들이 엎드린다"]'::jsonb, '[["jesus"], ["moses", "elijah", "jesus"], ["peter"], []]'::jsonb, ARRAY['jesus', 'peter', 'james', 'john', 'moses', 'elijah']::text[], '[{"book": "막", "from": "9:2", "to": "9:13"}, {"book": "마", "from": "17:1", "to": "17:13"}, {"book": "눅", "from": "9:28", "to": "9:36"}]'::jsonb, 29, 29, 'approx', 15, 'lm_nt_pm_mt_transfiguration', 'published'),
    ('era_patriarch', '축복 가로채기: 속임수의 밤', '야곱은 속임수로 이삭의 축복을 받고 도망길에 오른다.', '["늙은 리브가가 급히 계획을 말하고 야곱이 망설인다", "야곱이 염소 가죽을 두르고 늙은 이삭 앞에 선다, 숨죽인 긴장", "에서가 이삭 앞에서 기도해 달라고 간청하지만, 이삭은 더 줄 축복이 없다는 듯 고개를 떨군다", "에서가 돌아와 울부짖고, 야곱은 짐을 챙겨 도망친다"]'::jsonb, '[["jacob", "rebekah"], ["jacob", "isaac"], ["esau", "isaac"], ["jacob", "esau"]]'::jsonb, ARRAY['jacob', 'esau', 'isaac', 'rebekah']::text[], '[{"book": "창", "from": "27:1", "to": "27:45"}]'::jsonb, -1985, -1985, 'approx', 15, 'lm_pat_beersheba', 'published'),
    ('era_divided_kingdom', '호세아의 몰락: 사마리아가 함락되다', '북이스라엘의 마지막 왕 호세아는 앗수르에 반역하다 붙잡히고, 사마리아는 함락되어 백성이 포로로 끌려간다.', '["사마리아 성 밖, 앗수르 왕 살만에셀이 많은 군대와 병거를 이끌고 호세아 왕을 잡으러 올라오고, 성벽 위의 호세아 왕은 두려움과 긴장 속에 바라보는 장면", "앗수르 왕이 호세아 왕의 배반을 알고 그를 붙잡아 어두운 감옥에 가둔 모습. 호세아는 왕복이 흐트러진 채 침울하게 앉아 있고, 피와 폭력은 보이지 않는다", "사마리아 성이 함락되고, 이스라엘 사람들이 가족과 짐을 들고 앗수르 병사들에게 이끌려 먼 앗수르 땅으로 끌려가는 장면. 북이스라엘 왕국이 끝났다는 침통한 분위기이며, 피와 시신은 보이지 않는다"]'::jsonb, '[["hoshea_king"], ["hoshea_king"], []]'::jsonb, ARRAY['hoshea_king']::text[], '[{"book": "왕하", "from": "17:1", "to": "17:6"}]'::jsonb, -724, -722, 'approx', 15, 'lm_div_samaria', 'published'),
    ('era_nt_apostolic', '2차 선교(1): 드로아에서 마게도냐로', '드로아에서 ‘마게도냐로 건너오라’는 인도를 받고 방향이 바뀐다.', '["바울 일행은 드로아에서 다음 길을 기다린다", "밤에 바울은 마게도냐로 오라는 환상을 본다", "일행은 그 인도를 따라 방향을 정한다", "배는 바다를 건너 새로운 땅으로 향한다"]'::jsonb, '[["paul", "silas", "timothy"], ["paul"], ["paul", "silas", "timothy"], ["paul", "silas", "timothy"]]'::jsonb, ARRAY['paul', 'silas', 'timothy']::text[], '[{"book": "행", "from": "16:6", "to": "16:10"}]'::jsonb, 49, 49, 'approx', 16, 'lm_nt_ap_troas', 'published'),
    ('era_monarchy', '다윗과 밧세바: 무너진 마음', '다윗은 왕궁에 머물며 은밀한 죄를 저지르고, 그 악함은 하나님 앞에 드러난다.', '["저녁 무렵 예루살렘 왕궁 옥상에서 다윗이 아래 뜰을 바라보다가, 낮은 가림막 뒤에서 물동이와 목욕 천으로 몸을 씻는 밧세바의 아름다운 모습을 보고 마음이 흔들리는 장면. 노출이나 선정적 묘사는 보이지 않는다", "왕궁 안, 다윗이 사자를 통해 밧세바를 불러들이고, 장면을 두 구역으로 나누어 한쪽에는 엄숙한 궁전 복도에서 밧세바가 다윗 앞에 서는 모습, 다른 쪽에는 시간이 지나 밧세바가 조심스럽게 배를 감싸며 임신 소식을 전하는 상징 장면. 침실이나 성적 장면은 보이지 않는다", "다윗이 요압에게 편지를 보내 우리아를 가장 위험한 전투 앞으로 세우게 하고, 멀리 성벽 아래 전쟁터에서는 우리아가 방패를 떨어뜨리며 쓰러진 사실이 전해지는 장면. 요압은 이름 없는 군대 지휘관으로 보이고, 피와 시신의 세부 묘사는 보이지 않는다", "전령이 우리아의 죽음 소식을 전하고 다윗은 무거운 얼굴로 서 있으며, 밧세바는 검소한 상복 차림으로 조용히 울고, 위쪽에는 하나님이 다윗의 악함을 보시는 듯한 엄중한 금빛과 붉은 빛이 왕궁을 비추는 장면. 하나님은 사람 형상으로 보이지 않고, 피와 시신은 보이지 않는다"]'::jsonb, '[["david"], ["david"], [], ["david", "god"]]'::jsonb, ARRAY['david', 'god']::text[], '[{"book": "삼하", "from": "11:1", "to": "11:27"}]'::jsonb, -990, -990, 'approx', 16, 'lm_mon_jerusalem', 'published'),
    ('era_exodus', '미리암과 아론: 모세를 비방하다', '모세를 향한 불평 속에서도 하나님은 겸손한 종을 세우시고 중보의 길을 보이신다.', '["하세롯의 광야 진영, 아론과 한 여인이 장막 앞에서 모세를 향해 불만을 드러내고, 모세는 조용히 듣고있는 장면", "회막 위에 구름기둥이 내려오고 하나님의 빛이 임하고 모세와 아론과 그 여인이 긴장한 표정으로 서있는 장면", "그 여인의 피부가 눈처럼 희어져 모세와 아론을 떠나 진영 밖으로 물러나고, 사람들은 두려워 하는 장면", "모세가 장막 밖에서 멀리 있는 그 하얀 얼굴과 피부를 가진 여인을 위해 간절히 중보하고, 여인의 회복을 기다리는 장면"]'::jsonb, '[["moses", "aaron"], ["god", "moses", "aaron"], ["moses", "aaron"], ["moses", "god"]]'::jsonb, ARRAY['moses', 'god', 'aaron']::text[], '[{"book": "민", "from": "12:1", "to": "12:16"}]'::jsonb, -1445, -1445, 'approx', 16, 'lm_exo_hazeroth', 'published'),
    ('era_nt_public_ministry', '베드로의 고백과 수난 예고', '베드로의 고백 이후 예수님은 십자가의 길을 처음으로 분명히 예고하신다.', '["길을 가던 예수와 제자들이 멈추고, 예수는 사람들이 자신을 누구라 하는지 물으신다", "베드로가 앞으로 나서서 예수는 그리스도라고 고백한다", "예수는 자신이 고난을 받고 죽임당한 뒤 다시 살아날 것을 처음으로 밝히신다", "베드로가 만류하자 예수는 제자들 앞에서 그의 생각을 바로잡으시고, 모두가 충격에 잠긴다"]'::jsonb, '[["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["peter"], ["jesus", "peter"], ["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "막", "from": "8:27", "to": "8:33"}, {"book": "마", "from": "16:13", "to": "16:23"}, {"book": "눅", "from": "9:18", "to": "9:22"}]'::jsonb, 29, 29, 'approx', 16, 'lm_nt_pm_caesarea_philippi', 'published'),
    ('era_patriarch', '벧엘의 꿈: 사다리와 약속', '도망자 야곱은 길 위에서 ‘함께하심’의 약속을 받는다.', '["야곱이 돌을 베고 누운다, 밤바람 소리만 들린다", "야곱이 하늘까지 닿아있는 사닥리에 천사들이 오르락 내리락하는 모습을 보고 놀라는 모습", "하나님의 빛이 야곱위로 임하여 자손이 동서남북으로 퍼지게 될 것이라는 약속을 하시고, 야곱은 놀라는 모습", "야곱이 돌기둥을 세우고 기름을 붓는다, 여기가 하나님의 집이라고 말하며 돌을 세우는 모습"]'::jsonb, '[["joseph", "jacob"], ["jacob"], ["jacob", "god"], ["jacob", "god"]]'::jsonb, ARRAY['jacob', 'god']::text[], '[{"book": "창", "from": "28:10", "to": "28:22"}]'::jsonb, -1985, -1985, 'approx', 16, 'lm_pat_bethel', 'published'),
    ('era_exile_return', '성벽 재건: 밤의 조사와 한 손엔 무기', '느헤미야는 밤에 성벽을 살핀 뒤 재건을 이끌었고, 백성은 한 손에 돌 한 손에 무기를 들고 성을 세웠다.', '["밤, 느헤미야가 소수와 함께 성벽을 따라 조사한다", "성벽을 재건하는 건축 현장", "건축 현장에서 한 손엔 돌, 한 손엔 무기를 들고 성벽을 세우는 모습", "나팔 소리에 사람들이 모이고, 하나님이 싸우신다는 외침에 모두가 고개를 드는 장면"]'::jsonb, '[["nehemiah"], ["nehemiah"], ["nehemiah"], ["nehemiah"]]'::jsonb, ARRAY['nehemiah']::text[], '[{"book": "느", "from": "2:11", "to": "2:20"}, {"book": "느", "from": "4:10", "to": "4:20"}]'::jsonb, -445, -445, 'approx', 16, 'lm_exi_jerusalem', 'published'),
    ('era_divided_kingdom', '히스기야와 산헤립: 두려움의 편지', '포위 속에서 히스기야는 편지를 성전에 펼치고 하나님께 매달린다.', '["성벽 아래 조롱", "엘리아김과 셉나와 요아가 히스기야에게 앗수르 군대와 랍사게의 조롱 이야기를 전하자, 히스기야가 울며 옷을 찢고 깊은 두려움과 슬픔에 빠지는 장면", "히스기야가 성전에서 주님께 울며 간절히 기도하고, 예루살렘을 둘러싼 두려운 상황을 하나님 앞에 맡기는 장면", "이사야가 히스기야에게 하나님의 말씀을 선포하고, 큰 글자 없는 말풍선 안에는 하나님이 악한 앗수르 왕과 그가 자랑하던 여러 왕들과 우상 성전들을 모두 물리치시며 예루살렘을 보호하시는 상징 그림이 담겨 있다"]'::jsonb, '[[], ["hezekiah"], ["hezekiah"], ["hezekiah", "isaiah"]]'::jsonb, ARRAY['hezekiah', 'isaiah']::text[], '[{"book": "왕하", "from": "18:13", "to": "19:19"}, {"book": "사", "from": "37:1", "to": "37:38"}]'::jsonb, -701, -701, 'approx', 16, 'lm_div_jerusalem', 'published'),
    ('era_nt_apostolic', '2차 선교(2): 빌립보—루디아와 감옥의 찬양', '빌립보에서 복음은 가정과 감옥 한복판까지 스며든다.', '["강가에서 루디아가 복음을 듣고 마음을 연다", "바울과 실라는 감옥에 갇히지만 밤중에도 찬양한다", "큰 흔들림 속에 옥문이 열리고 간수는 두려워한다", "간수의 집은 말씀을 듣고 하나님을 믿게 되며 기쁨으로 가득해진다"]'::jsonb, '[["paul", "silas", "timothy", "lydia"], ["paul", "silas"], ["paul", "silas"], ["paul", "silas", "lydia"]]'::jsonb, ARRAY['paul', 'silas', 'timothy', 'lydia']::text[], '[{"book": "행", "from": "16:11", "to": "16:34"}]'::jsonb, 50, 50, 'approx', 17, 'lm_nt_ap_philippi', 'published'),
    ('era_exodus', '가나안 정탐: 믿음과 두려움의 갈림길', '정탐꾼들의 보고 앞에서 백성은 두려움에 흔들리지만, 하나님은 믿음 없는 세대의 광야 길을 선언하신다.', '["가데스 바네아 진영에서 모세가 가나안 땅을 정탐할 대표들을 보내고, 여호수아와 갈렙과 여러 정탐꾼들이 광야 길을 향해 출발한다", "여호수아와 갈렙을 포함한 정탐꾼들이 에스골 골짜기에서 큰 포도송이를 장대에 매달아 둘이 함께 들고 돌아오고, 멀리 가나안의 풍성한 골짜기가 보인다", "두려움에 찬 정탐꾼들이 견고한 성읍과 거대한 사람들을 손짓으로 설명하자 백성이 술렁이고, 여호수아와 갈렙은 믿음으로 백성을 진정시키려 하는 모습을 모세가 보고있다", "밤의 진영에서 백성이 낙심해 웅성거리고, 회막에는 하나님의 영광이 밝게 임하며, 모세가 백성을 위해 엎드려 중보한다. 하나님의 영광에서 나오는 큰 말풍선 안에는 광야 길에서 이스라엘 백성들이 오래 고생하며 걷고 장막 곁에서 지쳐 쉬는 상징 그림이 글자 없이 담겨 있다"]'::jsonb, '[["moses", "joshua", "caleb"], ["joshua", "caleb"], ["joshua", "moses", "caleb"], ["god", "moses"]]'::jsonb, ARRAY['moses', 'god', 'joshua', 'caleb']::text[], '[{"book": "민", "from": "13:1", "to": "14:45"}]'::jsonb, -1445, -1445, 'approx', 17, 'lm_exo_eshcol_valley', 'published'),
    ('era_monarchy', '나단의 책망: 그 사람이라', '나단은 비유로 다윗의 죄를 드러내고, 다윗은 아이를 위해 하나님 앞에 엎드린다.', '["예루살렘 왕궁에서 나단 선지자가 다윗 앞에 서서 비유를 들려주고, 큰 글자 없는 말풍선 안에는 많은 양을 가진 부자가 가난한 사람의 작은 어린 양을 빼앗아 가는 그림이 담겨 있다", "다윗이 왕좌에서 일어나 의로운 분노로 나단에게 그 부자는 잘못했고 네 배로 갚아야 한다고 말하며, 큰 글자 없는 말풍선 안에는 부자가 가난한 사람에게 어린 양 네 마리를 돌려주는 그림이 담겨 있다", "나단이 다윗을 향해 단호하게 손가락질하며 책망하고, 다윗은 충격으로 굳어 있다. 큰 글자 없는 말풍선 안에는 병든 아기를 상징하는 어두운 빈 요람과 꺼져 가는 작은 등불이 보인다. 죽음이나 시신은 직접 보이지 않는다", "다윗이 왕궁 바닥에 엎드려 금식하며 하나님께 아이를 살려 달라고 밤새 기도하고, 신하들은 멀리서 걱정스럽게 지켜본다. 위쪽에는 사람 형상 없는 하나님의 조용한 빛이 드리운다"]'::jsonb, '[["david", "nathan"], ["david", "nathan"], ["david", "nathan"], ["david", "god"]]'::jsonb, ARRAY['david', 'nathan', 'god']::text[], '[{"book": "삼하", "from": "12:1", "to": "12:23"}]'::jsonb, -990, -990, 'approx', 17, 'lm_mon_jerusalem', 'published'),
    ('era_patriarch', '라반의 집: 레아와 라헬', '야곱은 라헬을 사랑하지만 속임수로 레아와도 결혼하게 된다.', '["우물가에서 라헬을 처음 본 야곱이 큰 돌을 옮긴다", "라반이 야곱과 계약을 맺고, 라반은 야곱보다 훨씬 늙어 보인다", "혼인 밤, 얼굴을 가린 신부를 두고 아침에 레아임을 알아차린 야곱이 충격을 받는다", "야곱이 다시 7년을 약속하고 라헬을 맞는다"]'::jsonb, '[["jacob", "rachel"], ["laban", "jacob"], ["jacob", "leah"], ["jacob", "rachel"]]'::jsonb, ARRAY['jacob', 'laban', 'leah', 'rachel']::text[], '[{"book": "창", "from": "29:1", "to": "29:30"}]'::jsonb, -1984, -1977, 'approx', 17, 'lm_pat_haran', 'published'),
    ('era_nt_public_ministry', '비유: 선한 사마리아인', '예수님은 선한 사마리아인 비유로 참된 이웃 사랑이 무엇인지 가르치신다.', '["율법교사가 예수께 다가와 내 이웃이 누구인지 묻는다", "길가에 쓰러진 사람, 제사장과 레위인이 지나친다", "사마리아인이 멈추어 상처를 싸매고 짐승에 태운다", "예수는 누가 이웃이 되었는지 되묻고, 율법교사는 자비를 베푼 사람이라고 답한다"]'::jsonb, '[[], [], [], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "눅", "from": "10:25", "to": "10:37"}]'::jsonb, 30, 30, 'approx', 17, 'lm_nt_pm_jericho', 'published'),
    ('era_exile_return', '율법 낭독: 울음에서 기쁨으로', '말씀이 낭독되자 백성은 울고, 지도자들은 ‘기쁨이 힘’이라 격려한다.', '["에스라가 군중들에게 두루마리를 선포하는 장면", "느헤미야가 울지 말라고 백성들을 다독이는 장면", "에스라와 느헤미야와 백성들이 음식을 나누며 기뻐하는 장면"]'::jsonb, '[["ezra"], ["nehemiah"], ["ezra", "nehemiah"]]'::jsonb, ARRAY['ezra', 'nehemiah']::text[], '[{"book": "느", "from": "8:1", "to": "8:12"}]'::jsonb, -444, -444, 'approx', 17, 'lm_exi_jerusalem', 'published'),
    ('era_divided_kingdom', '히스기야의 병과 바벨론 사신', '회복 이후의 자랑은 또 다른 위기를 예고한다.', '["히스기야가 병상에서 울며 기도하는 장면", "이사야가 히스기야에게 와서 나을 것이라고 말하는 장면", "히스기야가 다 나은 뒤 바벨론 사신들에게 보물을 자랑하는 장면", "이사야가 히스기야에게 보물을 가리키며 호통치는 장면"]'::jsonb, '[["hezekiah"], ["hezekiah", "isaiah"], ["hezekiah"], ["hezekiah", "isaiah"]]'::jsonb, ARRAY['hezekiah', 'isaiah']::text[], '[{"book": "왕하", "from": "20:1", "to": "20:19"}, {"book": "사", "from": "38:1", "to": "39:8"}]'::jsonb, -700, -700, 'approx', 17, 'lm_div_jerusalem', 'published'),
    ('era_nt_apostolic', '2차 선교(3): 데살로니가—소동과 도피', '데살로니가에서 복음이 퍼지자 반대가 폭동으로 번진다.', '["바울 일행은 회당에서 복음을 전한다", "몇 사람은 믿지만 반대의 목소리도 커진다", "도시에는 소동이 일어나고 긴장이 번진다", "형제들은 밤에 바울 일행을 급히 피신시킨다"]'::jsonb, '[["paul", "silas", "timothy"], ["paul", "silas", "timothy"], ["paul", "silas", "timothy"], ["paul", "silas", "timothy"]]'::jsonb, ARRAY['paul', 'silas', 'timothy']::text[], '[{"book": "행", "from": "17:1", "to": "17:9"}]'::jsonb, 50, 50, 'approx', 18, 'lm_nt_ap_thessalonica', 'published'),
    ('era_exodus', '고라의 반역: 권위에 맞서다', '거룩한 직분을 둘러싼 반역 속에서 하나님은 공동체의 질서를 분명히 세우신다.', '["광야 진영에서 고라와 몇 사람이 모세와 아론 앞에 서서 반기를 들고, 모세는 엄중한 표정으로 그들을 마주한다", "회막 입구에서 모세가 바라보는 가운데 고라와 반역자들이 각기 향로를 가져다가 불과 향을 넣고 서 있으며, 아론도 향로를 들고 있고 회막 위에는 하나님의 영광이 밝게 나타난다", "고라와 반역자들이 그들의 소유와 함께 갈라진 땅 사이로 떨어지고, 모세와 아론은 깊은 틈 가장자리에서 두려움과 엄중함으로 지켜본다. 시신이나 피는 직접 보이지 않는다"]'::jsonb, '[["moses", "aaron"], ["god", "moses", "aaron"], ["moses", "aaron"]]'::jsonb, ARRAY['moses', 'god', 'aaron']::text[], '[{"book": "민", "from": "16:1", "to": "16:50"}]'::jsonb, -1445, -1445, 'approx', 18, 'lm_exo_kadesh_barnea', 'published'),
    ('era_nt_public_ministry', '비유: 탕자의 귀환', '잃은 아들을 맞이하는 아버지의 품이 하나님 나라의 심장을 드러낸다.', '["작은아들이 아버지에게 유산을 요구한 뒤 집을 떠나 먼 나라로 간다", "재산을 다 써버린 아들은 굶주림 속에 돼지우리에서 비참한 처지를 깨닫는다", "집으로 돌아오는 아들을 본 아버지는 먼저 달려가 끌어안고 잔치를 준비한다", "큰아들은 돌아온 동생을 위한 잔치에 마음이 상하지만, 아버지는 함께 기뻐하자고 권한다"]'::jsonb, '[[], [], [], []]'::jsonb, ARRAY['jesus']::text[], '[{"book": "눅", "from": "15:11", "to": "15:32"}]'::jsonb, 30, 30, 'approx', 18, 'lm_nt_pm_perea', 'published'),
    ('era_monarchy', '암논과 다말: 압살롬의 분노', '암논의 죄와 다말의 눈물은 압살롬의 분노로 이어지고, 다윗의 집에는 깊은 상처가 남는다.', '["예루살렘 왕궁 뜰, 다윗의 아들 암논이 20대 왕자 모습으로 다말을 집요하게 바라보며 따라가고, 20대 공주 다말은 화려한 채색 긴 옷을 입고 불편한 표정으로 거리를 두는 장면. 성적 묘사는 전혀 보이지 않는다", "암논이 병든 척 침대에 누워 있고, 다말이 구운 빵과 과자를 들고 방 안으로 들어오자 암논이 손목을 붙잡아 침상 쪽으로 끌어당기려 하며 다말은 놀라 뒤로 물러나는 장면. 침실 장면은 위협의 순간만 보이고 성폭력 행위나 노출은 직접 보이지 않는다", "머리에 재를 얹고 찢어진 채색 옷을 붙든 다말이 압살롬의 집으로 와서 울고, 20대 후반의 압살롬은 긴 머리와 왕자 복장으로 다말을 보호하듯 감싸며 분노를 억누르는 장면", "세로 3등분 구도: 위에는 바알하솔 잔치에서 압살롬의 부하들이 암논에게 포도주를 권하고 암논이 취해 앉아 있는 모습, 가운데에는 부하들이 암논에게 달려들어 심판이 벌어지는 순간을 멀리서 보여주되 피와 상처는 보이지 않는 모습, 아래에는 60대 초반 다윗이 궁전에서 소식을 듣고 옷을 찢으며 통곡하고, 긴 머리의 압살롬은 먼 길로 도망하는 모습"]'::jsonb, '[[], [], ["absalom"], ["david", "absalom"]]'::jsonb, ARRAY['david', 'absalom']::text[], '[{"book": "삼하", "from": "13:1", "to": "13:39"}]'::jsonb, -987, -985, 'approx', 18, 'lm_mon_jerusalem', 'published'),
    ('era_patriarch', '열두 아들의 시작: 이름에 담긴 마음', '경쟁과 상처 속에서도 열두 지파의 뿌리가 형성된다.', '["레아가 남자 아이 6명과 딸 1명을 낳은 모습", "라헬은 질투하여 시녀 빌하를 야곱과 동침하게 하여 아들을 2명 낳은 모습", "레아는 시녀 실바를 야곱과 동침하게 아들을 2명 더 낳은 모습", "하나님이 라헬의 태를 열어주사, 라헬이 요셉을 낳았고, 요셉을 안고 안도의 숨을 쉬는 모습"]'::jsonb, '[["leah"], ["rachel"], ["leah"], ["rachel"]]'::jsonb, ARRAY['jacob', 'leah', 'rachel']::text[], '[{"book": "창", "from": "29:31", "to": "30:24"}]'::jsonb, -1977, -1965, 'approx', 18, 'lm_pat_haran', 'published'),
    ('era_divided_kingdom', '요시야의 개혁: 율법책을 찾다', '어린 나이에 왕이 된 요시야는 여호와의 길을 따르고, 발견된 율법책 앞에서 회개하며 유다의 우상 숭배를 정리한다.', '["8살의 어린 요시야가 예루살렘에서 왕으로 세워지고, 다윗의 길을 따라 여호와 보시기에 정직히 행하자 하나님이 기뻐하시는 따뜻한 영광의 빛이 어린 왕과 왕궁 위에 임하는 장면", "왕위 18년, 약 26세의 요시야 왕이 미장공과 목수와 건축자들에게 성전 보수를 맡긴 가운데, 대제사장 힐기야가 성전 안에서 오래 잊힌 율법책 두루마리를 발견하고 놀라는 장면", "서기관 사반이 율법책을 약 26세의 요시야 왕 앞에서 읽어 주자, 요시야가 눈물로 옷을 찢으며 하나님께 부르짖고, 신하들은 충격을 받아 조용히 서 있는 장면", "약 26세의 요시야 왕이 백성들 앞에서 율법책을 낭독하고 언약을 세우며, 주변에서는 군사들과 제사장들이 바알 신상과 아세라 목상을 부수어 성전 밖으로 치우는 장면. 피와 폭력은 보이지 않고, 글자는 읽히지 않는다"]'::jsonb, '[["josiah"], ["josiah"], ["josiah"], ["josiah"]]'::jsonb, ARRAY['josiah']::text[], '[{"book": "왕하", "from": "22:1", "to": "22:13"}, {"book": "왕하", "from": "23:1", "to": "23:21"}]'::jsonb, -622, -622, 'approx', 18, 'lm_div_jerusalem', 'published')
)
insert into events (era_id, title, summary, story_scenes, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.story_scenes,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  story_scenes = excluded.story_scenes,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, story_scenes, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, landmark_code, status) as (
  values
    ('era_nt_apostolic', '2차 선교(4): 베뢰아—말씀을 상고하다', '베뢰아 사람들은 말씀을 상고하며 복음을 받아들인다.', '["베뢰아 사람들은 열린 마음으로 말씀을 듣는다", "그들은 두루마리를 펴고 날마다 확인한다", "많은 이가 믿지만 방해도 다시 따라온다", "바울은 떠나고 실라와 디모데는 남아 돕는다"]'::jsonb, '[["paul", "silas", "timothy"], ["paul", "silas", "timothy"], ["paul", "silas", "timothy"], ["paul", "silas", "timothy"]]'::jsonb, ARRAY['paul', 'silas', 'timothy']::text[], '[{"book": "행", "from": "17:10", "to": "17:15"}]'::jsonb, 50, 50, 'approx', 19, 'lm_nt_ap_berea', 'published'),
    ('era_nt_public_ministry', '나사로의 부활', '예수님은 ‘나는 부활이요 생명’이라 하시며 나사로를 일으키신다.', '["베다니에 슬픔이 가득하고, 마르다와 마리아 곁에 사람들이 모여 있다", "마르다가 예수를 맞으며 조용히 말을 건넨다", "예수는 무덤 앞에 서서 돌을 옮기게 하신다", "예수의 부르심에 나사로가 나오고, 사람들은 놀란다"]'::jsonb, '[["martha", "mary"], ["jesus", "martha"], ["jesus"], ["jesus", "lazarus"]]'::jsonb, ARRAY['jesus', 'lazarus', 'martha', 'mary']::text[], '[{"book": "요", "from": "11:1", "to": "11:44"}]'::jsonb, 32, 32, 'approx', 19, 'lm_nt_pm_bethany', 'published'),
    ('era_exodus', '므리바 물: 바위를 치다', '물 없는 광야에서 하나님은 반석의 물을 주시지만, 모세와 아론은 하나님의 거룩함을 드러내지 못한다.', '["백성들이 광야 진영에서 모세와 아론을 향해 물이 없다고 불평하며 몰려오고, 모세와 아론은 근심스러운 얼굴로 서 있다", "회막 앞에 하나님의 영광이 밝게 임하고, 하나님이 모세에게 지팡이를 들고 바위에 말하면 물이 나올 것임을 큰 글자 없는 말풍선 속 그림으로 보여 주신다", "모세가 지팡이로 바위를 두 번 내리치자 물이 바위에서 세차게 터져 나오고, 백성과 가축들이 놀라며 물가로 모여든다", "하나님의 영광이 모세와 아론 앞에 임하고, 큰 글자 없는 말풍선 안에는 젖과 꿀이 흐르는 풍성한 땅이 멀리 보이지만 그 앞에는 닫힌 문과 빛나는 경계선이 길을 막고 있으며, 모세와 아론은 경계선 밖에서 고개를 숙인 채 멈춰 서 있는 상징 그림이 담겨 있다"]'::jsonb, '[["moses", "aaron"], ["god", "moses", "aaron"], ["moses", "aaron"], ["god", "moses", "aaron"]]'::jsonb, ARRAY['moses', 'god', 'aaron']::text[], '[{"book": "민", "from": "20:1", "to": "20:13"}]'::jsonb, -1408, -1408, 'approx', 19, 'lm_exo_kadesh_barnea', 'published'),
    ('era_monarchy', '압살롬의 귀환: 멀어진 아버지', '요압의 계책과 드고아 여인의 비유를 통해 압살롬은 돌아오지만, 부자의 관계는 쉽게 회복되지 않는다.', '["상복을 입은 드고아의 젊은 지혜로운 여인이 60대 초반 다윗 왕 앞에 엎드려 슬픈 얼굴로 자기 사정을 말하고, 큰 글자 없는 말풍선 안에는 들판에서 한 아들이 다른 아들을 쓰러뜨린 뒤 도망가는 그림이 담겨 있다. 폭력의 세부 묘사는 보이지 않는다", "60대 초반의 다윗이 왕좌에서 드고아 여인에게 손을 들어 보호를 약속하고, 큰 글자 없는 말풍선 안에는 도망간 아들이 안전하게 집으로 돌아오며 왕의 보호 빛 아래 서 있는 그림이 담겨 있다", "드고아 여인이 60대 초반의 다윗을 향해 조심스럽지만 단호하게 손짓하며 말하고, 큰 글자 없는 말풍선 안에는 긴 머리의 압살롬을 예루살렘으로 데려와야 한다는 상징 그림이 담겨 있다. 다윗은 깨달은 표정으로 굳어 있다", "예루살렘 왕궁 안, 60대 초반의 다윗이 30대의 긴 머리 압살롬을 불러 끌어안고 입맞추며 맞이하지만, 두 사람 사이에는 아직 어색한 침묵과 거리감이 남아 있는 장면"]'::jsonb, '[["david"], ["david"], ["david", "absalom"], ["david", "absalom"]]'::jsonb, ARRAY['david', 'absalom']::text[], '[{"book": "삼하", "from": "14:1", "to": "14:33"}]'::jsonb, -984, -982, 'approx', 19, 'lm_mon_jerusalem', 'published'),
    ('era_patriarch', '야곱의 번성: 양떼의 기묘한 계약', '야곱은 라반의 집에서 번성하고 라반과 갈등이 깊어진다.', '["야곱이 떠나겠다고 말하자 라반이 붙잡는다", "양떼 계약이 정해지고, 야곱이 표식을 구분한다", "야곱의 떼가 늘어나며 라반의 얼굴이 굳는다", "야곱이 가족에게 속삭인다, 이제 떠나야 한다"]'::jsonb, '[["jacob", "laban"], ["jacob"], ["jacob", "laban"], ["jacob"]]'::jsonb, ARRAY['jacob', 'laban']::text[], '[{"book": "창", "from": "30:25", "to": "31:16"}]'::jsonb, -1965, -1961, 'approx', 19, 'lm_pat_haran', 'published'),
    ('era_divided_kingdom', '예레미야의 경고: 칠십 년의 포로', '예레미야는 유다가 말씀을 듣지 않았기에 바벨론을 섬기게 되지만, 정한 때가 차면 바벨론도 심판받을 것이라고 선포한다.', '["예레미야 선지자가 유다 백성 앞에서 엄중히 말하고, 큰 말풍선 안에는 예루살렘이 폐허가 되고 백성들이 바벨론 왕을 섬기는 장면이 보인다. 말풍선 안에는 큰 숫자 70만 또렷하게 보이고 다른 글자는 없다", "예레미야 선지자가 백성들에게 계속 선포하고, 큰 글자 없는 말풍선 안에는 칠십 년 뒤 바벨론 왕과 그 나라가 하나님의 처벌을 받아 왕좌와 성읍이 무너지는 상징 그림이 보인다. 피와 시신은 보이지 않는다"]'::jsonb, '[["jeremiah"], ["jeremiah"]]'::jsonb, ARRAY['jeremiah']::text[], '[{"book": "렘", "from": "25:1", "to": "25:14"}]'::jsonb, -605, -605, 'approx', 19, 'lm_div_jerusalem', 'published'),
    ('era_nt_apostolic', '2차 선교(5): 아덴—아레오바고 설교', '바울은 ‘알지 못하는 신’ 제단을 출발점으로 창조주와 부활을 선포한다.', '["아덴의 거리는 우상으로 가득하고 바울은 깊이 생각한다", "바울은 사람들과 토론하며 아레오바고에 선다", "그는 알지 못하는 신을 말하며 창조주를 전한다", "부활의 말을 들은 사람들은 서로 다른 반응을 보인다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "17:16", "to": "17:34"}]'::jsonb, 51, 51, 'approx', 20, 'lm_nt_ap_athens', 'published'),
    ('era_exodus', '놋뱀: 바라보라', '원망 속에서 고통이 번지지만, 하나님은 ‘바라봄’으로 살 길을 주신다.', '["백성이 모세를 둘러싸고 원망을 쏟아낸다, 왜 우리를 이 광야로 데려왔느냐", "불뱀들이 진영에 나타나 백성을 물어 사람들이 공포에 빠진다, 피나 상처는 직접 보이지 않음", "모세가 장대를 세우고 표징을 올린다", "사람들이 고개를 들어 바라본다, 얼굴이 서서히 안정된다"]'::jsonb, '[[], [], ["moses"], []]'::jsonb, ARRAY['moses']::text[], '[{"book": "민", "from": "21:4", "to": "21:9"}]'::jsonb, -1408, -1408, 'approx', 20, 'lm_exo_edom_road', 'published'),
    ('era_patriarch', '도피와 언약: 라반과의 마지막', '야곱은 라반을 떠나고, 추격 끝에 언약으로 갈등을 마무리한다.', '["야곱이 밤에 장막을 접고 몰래 길을 나선다", "라반이 분노한 얼굴로 야곱을 추격해 따라잡는다", "야곱과 라반이 격한 말다툼 끝에 돌무더기를 쌓아 경계 표를 만든다", "라반이 딸들(라헬과 레아)과 손주들에게 입맞추고 축복하고 야곱을 떠나는 장면"]'::jsonb, '[["jacob"], ["jacob", "laban"], ["jacob", "laban"], ["jacob", "laban", "leah", "rachel"]]'::jsonb, ARRAY['jacob', 'laban', 'leah', 'rachel']::text[], '[{"book": "창", "from": "31:17", "to": "31:55"}]'::jsonb, -1961, -1961, 'approx', 20, 'lm_pat_gilead', 'published'),
    ('era_divided_kingdom', '새 언약의 약속: 마음에 새기다', '예레미야는 무너진 백성에게 회복과 새 언약을 전하며, 하나님이 말씀을 마음에 새기실 날을 바라보게 한다.', '["예레미야가 백성들에게 회복의 약속을 말하고, 큰 글자 없는 말풍선 안에는 이스라엘 백성들이 소고를 들고 춤추며, 포도나무 열매를 먹고, 모두가 기뻐하는 모습이 보인다", "예레미야가 백성들에게 말하고, 큰 글자 없는 말풍선 안에는 하나님이 보내신 선한 목자가 양 떼를 모아 안전하게 지키는 모습이 보인다", "예레미야가 백성들에게 강하게 말하고, 큰 글자 없는 말풍선 안에는 하나님이 타락한 예루살렘 백성들에게 돌아오라고 부르시며 회개를 촉구하는 상징 그림이 보인다. 백성들은 우상에서 돌아서려는 모습이다", "예레미야가 백성들에게 새 언약을 말하고, 큰 글자 없는 말풍선 안에는 하나님의 빛이 백성들의 마음 가운데 율법을 새기고 서 있는 모습이 보인다"]'::jsonb, '[["jeremiah"], ["jeremiah"], ["jeremiah"], ["jeremiah"]]'::jsonb, ARRAY['jeremiah']::text[], '[{"book": "렘", "from": "31:1", "to": "31:40"}]'::jsonb, -587, -587, 'approx', 20, 'lm_div_jerusalem', 'published'),
    ('era_monarchy', '압살롬의 반역: 감람산의 눈물', '압살롬은 백성의 마음을 빼앗아 반역을 일으키고, 다윗은 눈물로 예루살렘을 떠난다.', '["헤브론 성문 근처, 30대의 긴 머리 압살롬이 병거와 말과 따르는 사람들을 세우고 몰래 반역을 도모하며, 주변 사람들의 손을 잡아 주지만 얼굴에는 사악하고 계산적인 미소가 드러나는 장면. 왕이 되었다는 글자나 깃발 문구는 보이지 않는다", "예루살렘을 떠나는 60대 초반 다윗이 가족과 충성스러운 신하들과 함께 슬픈 표정으로 도망가고, 사독과 아비아달 제사장도 침통한 얼굴로 언약궤를 메고 서 있으며, 다윗이 제사장들에게 성쪽을 가리키며 언약궤를 다시 성으로 돌아가게 하라고 손짓하는 장면", "감람산 길, 침통한 표정의 백성들이 다윗과 함께 울며 산을 오르고, 60대 초반 다윗은 신하 후새를 향해 침통하지만 단호한 표정으로 손으로 막아서며 예루살렘 궁전 방향을 가리키며 돌아가 압살롬 곁에서 아히도벨의 모략을 막아 달라고 부탁하는 장면", "예루살렘 궁정 회의에서 노년의 신하 후새와 아히도벨이 압살롬 앞에서 조언한다. 후새의 마음속에는 다윗이 희미한 투명 이미지로 보이고, 압살롬은 악한 표정으로 후새의 조언을 선택한다. 곁의 아히도벨은 낙담한 표정을 짓는다. 죽음 장면은 보이지 않는다"]'::jsonb, '[["absalom"], ["david"], ["david"], ["absalom"]]'::jsonb, ARRAY['david', 'absalom']::text[], '[{"book": "삼하", "from": "15:1", "to": "15:37"}, {"book": "삼하", "from": "17:1", "to": "17:23"}]'::jsonb, -979, -979, 'approx', 20, 'lm_mon_jerusalem', 'published'),
    ('era_nt_public_ministry', '예루살렘 입성', '예수님은 겸손한 왕으로 입성하시고 군중은 환호한다.', '["감람산 길에서 제자들이 나귀를 끌고 온다", "예수는 나귀를 타고 예루살렘으로 들어가신다", "군중은 길에 옷과 가지를 펴고 호산나를 외친다", "예수는 성을 바라보며 잠시 걸음을 멈추신다"]'::jsonb, '[["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], [], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "막", "from": "11:1", "to": "11:11"}, {"book": "마", "from": "21:1", "to": "21:11"}, {"book": "눅", "from": "19:28", "to": "19:40"}, {"book": "요", "from": "12:12", "to": "12:19"}]'::jsonb, 33, 33, 'approx', 20, 'lm_nt_pm_jerusalem', 'published'),
    ('era_nt_apostolic', '2차 선교(6): 고린도—정착과 견딤', '고린도에서 바울은 오래 머물며 공동체를 세우고 박해를 견딘다.', '["바울은 아굴라와 브리스길라를 만나 함께 지낸다", "그는 일하며 꾸준히 복음을 전한다", "반대와 재판 속에서도 바울은 물러서지 않는다", "바울은 고린도를 떠나 다음 여정을 향해 길을 나선다"]'::jsonb, '[["paul", "aquila"], ["paul", "aquila"], ["paul"], ["paul", "aquila"]]'::jsonb, ARRAY['paul', 'aquila']::text[], '[{"book": "행", "from": "18:1", "to": "18:18"}]'::jsonb, 51, 52, 'approx', 21, 'lm_nt_ap_corinth', 'published'),
    ('era_exodus', '바알브올: 언약을 더럽히다', '이스라엘은 모압 평지에서 유혹과 우상 제사에 흔들리지만, 하나님은 언약의 거룩함을 다시 세우신다.', '["싯딤의 모압 평지에서 이스라엘 백성들이 모압 여인들과 우상 제사 잔치에 어울려 언약을 잊고 타락하는 모습. 장면 가운데나 뒤쪽에는 바알브올을 상징하는 글자 없는 돌 우상과 낮은 제단이 분명히 세워져 있고, 사람들이 그 주변에 모여 있다. 노골적인 성적 묘사는 보이지 않는다", "한 이스라엘 사람이 미디안 여인을 사람들이 보는 앞에서 천막 안으로 데리고 들어가고, 비느하스는 창을 들고 그 천막 입구로 급히 뒤따라 들어간다. 천막 안쪽은 가려져 있고 직접적인 죽음이나 피는 보이지 않는다", "하나님의 영광이 모세에게 임하고, 큰 글자 없는 말풍선 안에는 진영의 어두운 재앙 기운이 멈추고 백성이 안도하며, 비느하스의 언약을 향한 열심 때문에 하나님의 노가 그친다는 상징 그림이 담겨 있다"]'::jsonb, '[[], [], ["god", "moses"]]'::jsonb, ARRAY['moses', 'god']::text[], '[{"book": "민", "from": "25:1", "to": "25:18"}]'::jsonb, -1408, -1408, 'approx', 21, 'lm_exo_baal_peor', 'published'),
    ('era_divided_kingdom', '불태워진 두루마리: 말씀을 거부하다', '예레미야의 말씀이 바룩의 두루마리에 기록되어 낭독되지만, 여호야김은 말씀을 잘라 불태우며 거부한다.', '["실내에서 예레미야 선지자가 바룩에게 하나님의 말씀을 전하고, 바룩은 낮은 책상 앞에서 예레미야가 말하는 내용을 긴 두루마리에 정성껏 적는 장면", "성전 뜰 앞에서 바룩이 두루마리를 펼쳐 백성들에게 선포하고, 사람들은 긴장한 표정으로 귀 기울인다. 두루마리에는 읽을 수 있는 글자가 보이지 않는다", "여호야김의 관료들이 바룩에게 다가와 두루마리를 달라고 요구하고, 바룩은 놀라지만 두루마리를 조심스럽게 내미는 장면", "겨울 왕궁 안, 여후디가 여호야김 왕 앞에서 두루마리를 읽고, 여호야김은 사악하고 완고한 얼굴로 작은 칼로 두루마리를 잘라 화롯불에 넣는다. 불은 두루마리만 태우고 사람에게 번지지 않는다"]'::jsonb, '[["jeremiah"], [], [], ["jehoiakim"]]'::jsonb, ARRAY['jeremiah', 'jehoiakim']::text[], '[{"book": "렘", "from": "36:1", "to": "36:26"}]'::jsonb, -605, -604, 'approx', 21, 'lm_div_jerusalem', 'published'),
    ('era_nt_public_ministry', '성전 정화', '예수님은 성전을 ‘기도의 집’으로 회복시키려 하신다.', '["성전 뜰은 장사하는 사람들과 돈 바꾸는 이들로 붐빈다", "예수는 장사하는 자들을 내쫓고 상을 엎으신다", "예수는 성전은 기도하는 집이라고 선언하신다", "성전은 조용해지고 사람들은 놀란다"]'::jsonb, '[[], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "막", "from": "11:15", "to": "11:19"}, {"book": "마", "from": "21:12", "to": "21:17"}, {"book": "눅", "from": "19:45", "to": "19:48"}, {"book": "요", "from": "2:13", "to": "2:17"}]'::jsonb, 33, 33, 'approx', 21, 'lm_nt_pm_jerusalem', 'published'),
    ('era_monarchy', '압살롬의 최후: 다윗의 통곡', '압살롬의 반역은 수풀에서 끝나고, 다윗은 원수보다 아들로 그를 통곡한다.', '["마하나임 성문 앞, 60대 초반 다윗이 전쟁터로 나갈 군대를 정비해 요압과 지휘관들에게 나누어 보내며, 압살롬을 죽이지 말고 반드시 생포해 데려오라고 단호하게 명령하는 장면. 다윗은 울지 않고 왕답게 곧게 서서 지휘한다", "에브라임 수풀의 큰 상수리나무 아래, 30대 압살롬의 긴 머리털이 굵은 가지에 걸려 공중에 매달리고 노새는 아래로 달아나며, 멀리 다윗의 군사들이 조심스럽게 다가오는 장면. 피와 상처는 보이지 않는다", "절제된 세로 2분할 장면: 한쪽에는 요압이 상수리나무 아래 압살롬에게 창을 겨누며 다가가는 모습이 멀리서 보이고, 다른 한쪽에는 군사들이 수풀 가운데 큰 구덩이 위에 돌무더기를 쌓는 모습. 피, 상처, 시신의 세부 묘사는 보이지 않는다", "성문 위 방으로 올라간 60대 초반 다윗에게 전령이 압살롬의 죽음 소식을 전하고, 다윗은 얼굴을 가리며 무너져 통곡하는 장면. 주변 신하들은 침묵하며 슬퍼한다"]'::jsonb, '[["david"], ["absalom"], ["absalom"], ["david"]]'::jsonb, ARRAY['david', 'absalom']::text[], '[{"book": "삼하", "from": "18:5", "to": "18:33"}]'::jsonb, -978, -978, 'approx', 21, 'lm_mon_ephraim_forest', 'published'),
    ('era_patriarch', '얍복강 씨름: 이스라엘', '야곱은 밤새 씨름하며 새 이름 ‘이스라엘’을 받는다.', '["강가의 어둠 속에서 야곱이 혼자 숨을 고른다", "천사 같은 신비한 존재가 야곱을 붙잡고 서로 씨름을 시작한다", "천사 같은 신비한 존재가 야곱의 엉덩이 뼈를 쳐서 쓰러뜨리며 야곱이 땅에 넘어진다", "이스라엘이라는 새 이름을 받은 야곱이 절뚝이며 동틀 무렵 선다"]'::jsonb, '[["jacob"], ["jacob"], ["jacob"], ["jacob"]]'::jsonb, ARRAY['jacob']::text[], '[{"book": "창", "from": "32:24", "to": "32:32"}]'::jsonb, -1960, -1960, 'approx', 21, 'lm_pat_jabbok', 'published'),
    ('era_nt_apostolic', '3차 선교(1): 에베소—확장과 충돌', '에베소에서 복음이 크게 확장되며 도시의 질서와도 충돌한다.', '["에베소에서 바울의 가르침이 널리 퍼져 간다", "많은 사람이 말씀을 듣고 삶을 돌이킨다", "복음의 영향이 커지자 도시에도 긴장이 생긴다", "소동이 일어나지만 말씀의 흐름은 멈추지 않는다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "19:1", "to": "19:41"}]'::jsonb, 53, 55, 'approx', 22, 'lm_nt_ap_ephesus', 'published'),
    ('era_exodus', '모압 언약: 마음을 돌이키라', '모세는 새 세대에게 광야 길을 돌아보게 하고, 하나님께 마음을 돌이켜 언약의 길을 걷도록 권면한다.', '["늙은 흰 머리의 모세가 모압 평지에서 백성들에게 광야 생활을 하나님이 인도하셨음을 말하고, 큰 글자 없는 말풍선 안에는 하나님이 백성을 먹이시고 전쟁에서 이기게 하신 장면들이 그림으로 보인다", "늙은 흰 머리의 모세가 백성들에게 우상을 만들지 말고 오직 하나님만 따르라고 말하고, 큰 글자 없는 말풍선 안에는 송아지 모양과 은금 우상이 흐릿하게 막혀 있는 상징 그림이 담겨 있다", "늙은 흰 머리의 모세가 백성들에게 오직 하나님만 따르라고 말하고, 큰 글자 없는 말풍선 안에는 하나님이 복을 주셔서 이스라엘 백성들이 풍요롭고 행복하게 사는 그림이 담겨 있다"]'::jsonb, '[["god", "moses"], ["moses"], ["god", "moses"]]'::jsonb, ARRAY['moses', 'god']::text[], '[{"book": "신", "from": "29:1", "to": "30:10"}]'::jsonb, -1406, -1406, 'approx', 22, 'lm_exo_plains_moab', 'published'),
    ('era_patriarch', '에서와 화해: 달려오는 형', '두려움으로 맞이한 재회는 포옹과 눈물로 풀린다.', '["야곱이 가족을 줄 세우고 멀리서 다가오는 에서와 무리를 보며 긴장한다", "에서와 무리가 다가오고 야곱이 땅에 엎드린다", "에서가 야곱을 껴안고 울고 야곱도 울음을 삼킨다"]'::jsonb, '[["jacob", "esau"], ["jacob", "esau"], ["jacob", "esau"]]'::jsonb, ARRAY['jacob', 'esau']::text[], '[{"book": "창", "from": "33:1", "to": "33:11"}]'::jsonb, -1960, -1960, 'approx', 22, 'lm_pat_jabbok', 'published'),
    ('era_monarchy', '인구조사와 제단: 다윗의 선택', '잘못된 자랑이 재앙을 부르고, 다윗은 값을 치르고 제단을 세운다.', '["늙은 왕 다윗이 군사들에게 인구 조사를 명하는 장면", "선견자 갓이 하얀 머리와 수염의 늙은 다윗에게 와서 하나님의 책망과 세 가지 재앙의 선택을 전하고, 다윗은 바닥에 엎드려 울며 괴로워하는 장면. 갓은 이름 없는 예언자 모습으로 보이고 글자는 보이지 않는다", "단에서부터 브엘세바까지 이스라엘 전역에 온역의 어두운 기운이 퍼지고 수많은 집과 마을이 비통해하는 장면. 위쪽에는 사람 형상 없는 하나님의 엄중한 심판 빛이 드리우며, 칠만 명의 죽음을 상징하되 시신과 피는 직접 보이지 않는다", "늙은 왕 다윗이 불이 타오르는 제단 앞에서 기도하며 재앙이 그치는 장면"]'::jsonb, '[["david"], ["david"], ["god"], ["david", "god"]]'::jsonb, ARRAY['david', 'god']::text[], '[{"book": "삼하", "from": "24:10", "to": "24:25"}]'::jsonb, -970, -970, 'approx', 22, 'lm_mon_jerusalem', 'published'),
    ('era_nt_public_ministry', '최후의 만찬', '예수님은 떡과 잔으로 새 언약을 세우시고 배신을 예고하신다.', '["다락방에 예수와 제자들이 함께 둘러앉는다", "예수는 떡과 잔을 나누시며 새 언약을 말씀하신다", "예수는 제자들 가운데 한 사람이 자신을 팔 것이라 하신다", "유다는 자리를 떠나고 방 안의 분위기는 무거워진다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["judas", "jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "막", "from": "14:12", "to": "14:26"}, {"book": "마", "from": "26:17", "to": "26:30"}, {"book": "눅", "from": "22:7", "to": "22:23"}, {"book": "요", "from": "13:1", "to": "13:30"}]'::jsonb, 33, 33, 'approx', 22, 'lm_nt_pm_jerusalem', 'published'),
    ('era_divided_kingdom', '토굴의 예레미야: 왕에게 전하다', '시드기야 때 예레미야는 거짓 고발로 갇히지만, 왕 앞에서도 바벨론에게 넘겨질 말씀을 굽히지 않는다.', '["예레미야가 시드기야 왕에게 말하고, 큰 글자 없는 말풍선 안에는 바벨론 군대가 다시 예루살렘으로 돌아와 싸우는 그림이 보인다. 시드기야는 불안한 표정으로 듣는다", "베냐민 성문에서 문지기 우두머리가 예레미야를 향해 배반자라고 소리치고, 예레미야 선지자는 억울하고 단호한 얼굴로 거짓말이라고 맞서 말하는 장면", "예레미야가 어둡고 좁은 토굴 속 감옥에 갇혀 앉아 있지만, 무너지지 않는 믿음으로 조용히 버티는 장면. 피와 폭력은 보이지 않는다", "시드기야 왕이 예레미야를 다시 불러 은밀히 묻고, 예레미야가 시드기야 왕에게 바벨론 왕의 손에 넘겨질 것이라고 전한다. 큰 글자 없는 말풍선 안에는 시드기야가 바벨론 왕 앞에 넘겨지는 상징 그림이 보인다"]'::jsonb, '[["jeremiah", "zedekiah"], ["jeremiah"], ["jeremiah"], ["jeremiah", "zedekiah"]]'::jsonb, ARRAY['jeremiah', 'zedekiah']::text[], '[{"book": "렘", "from": "37:1", "to": "37:21"}]'::jsonb, -588, -588, 'approx', 22, 'lm_div_jerusalem', 'published')
)
insert into events (era_id, title, summary, story_scenes, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.story_scenes,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  story_scenes = excluded.story_scenes,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, story_scenes, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, landmark_code, status) as (
  values
    ('era_nt_apostolic', '3차 선교(2): 마게도냐—교회를 굳게 하다', '바울은 마게도냐를 돌며 성도들을 격려하고 공동체를 세운다.', '["바울은 여러 도시를 다시 찾아간다", "그는 성도들을 만나 말씀으로 격려한다", "공동체들은 다시 힘을 얻고 굳게 선다", "바울은 다음 여정을 향해 계속 나아간다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "20:1", "to": "20:2"}]'::jsonb, 56, 56, 'approx', 23, 'lm_nt_ap_philippi', 'published'),
    ('era_nt_public_ministry', '겟세마네: 뜻이 이루어지다', '예수님은 고뇌 속에서 아버지의 뜻에 자신을 맡기신다.', '["예수는 제자들과 함께 겟세마네로 들어가신다", "예수는 홀로 아버지의 뜻을 구하며 기도하신다", "돌아와 보니 제자들은 잠들어 있다", "예수는 기도를 마치고 다가올 일을 맞으러 일어나신다"]'::jsonb, '[["jesus", "peter", "james", "john"], ["jesus"], ["jesus", "peter", "james", "john"], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'james', 'john']::text[], '[{"book": "막", "from": "14:32", "to": "14:42"}, {"book": "마", "from": "26:36", "to": "26:46"}, {"book": "눅", "from": "22:39", "to": "22:46"}]'::jsonb, 33, 33, 'approx', 23, 'lm_nt_pm_gethsemane', 'published'),
    ('era_patriarch', '벧엘 귀환: 라헬의 죽음', '야곱의 가정은 이동 중 큰 상실을 겪고도 약속의 길을 이어간다.', '["하나님의 음성이 야곱에게 벧엘로 가라 명하셨고, 야곱은 길을 떠났고, 주변 아무도 그들을 쫓아오지 못하게 하나님이 막으시는 모습", "길 위에서 라헬이 진통하고 그 곁에 선 야곱이 초조하게 지켜본다", "라헬의 숨이 가늘어지고 갓난 베냐민 옆에서 야곱이 비통한 얼굴로 서 있다", "야곱이 무덤 기둥을 세우고 오래 서 있다"]'::jsonb, '[["god", "jacob"], ["rachel", "jacob"], ["rachel", "benjamin", "jacob"], ["jacob"]]'::jsonb, ARRAY['jacob', 'rachel', 'benjamin']::text[], '[{"book": "창", "from": "35:1", "to": "35:20"}]'::jsonb, -1955, -1955, 'approx', 23, 'lm_pat_bethlehem', 'published'),
    ('era_monarchy', '솔로몬 즉위: 왕의 노새', '밧세바와 나단의 요청 뒤에 다윗은 솔로몬을 왕으로 세우고, 솔로몬은 아도니야를 단호하지만 절제 있게 대한다.', '["늙은 밧세바가 아주 늙어 침상에 누운 다윗 왕에게 다가와 말하고, 큰 글자 없는 말풍선 안에는 아도니야가 스스로 왕위에 오르려 잔치를 벌이고 솔로몬이 위험해지는 그림이 담겨 있다. 다윗은 약해 보이지만 정신을 차려 듣는다", "기혼 샘 근처, 젊은 솔로몬이 다윗 왕의 노새를 타고 왕으로 세워지며 사독과 나단이 기름을 붓고, 백성들이 양각 나팔 소리와 함께 크게 환호하는 장면", "아도니야가 두려워 제단 뿔을 붙잡고 떨고 있고, 젊은 솔로몬은 왕좌 앞에서 아도니야를 해치지 않겠다고 단호하지만 절제 있게 말하는 장면. 폭력이나 피는 보이지 않는다"]'::jsonb, '[["david"], ["solomon"], ["solomon"]]'::jsonb, ARRAY['solomon', 'david']::text[], '[{"book": "왕상", "from": "1:1", "to": "1:53"}]'::jsonb, -970, -970, 'approx', 23, 'lm_mon_jerusalem', 'published'),
    ('era_exodus', '여호수아 위임: 강하고 담대하라', '모세는 마지막 때에 여호수아를 다음 지도자로 세우고, 백성에게 말씀을 끝까지 붙들라고 당부한다.', '["120세의 흰 머리 모세가 여호수아와 백성들이 있는 자리에서 여호수아를 다음 리더로 세우고, 여호수아는 겸손하지만 담대하게 선다", "120세의 모세와 여호수아가 회막에서 하나님의 거룩한 구름기둥 앞에 엎드려 말씀을 듣는다. 구름기둥은 하늘에서 회막 입구까지 내려온 크고 밝은 수직 기둥이며, 안쪽에서 순백색과 금빛 빛이 흘러나와 회막과 두 사람을 환하게 비춘다. 사람 형상이나 얼굴은 없고, 빛나는 구름 자체가 하나님의 임재처럼 느껴진다. 큰 글자 없는 말풍선 안에는 이스라엘이 훗날 하나님을 떠나 타락하는 어두운 상징 그림이 담겨 있다", "120세의 흰 머리 모세가 이스라엘 백성들에게 하나님을 끝까지 믿으라고 마지막으로 당부하고, 백성들은 조용히 귀 기울인다"]'::jsonb, '[["moses", "joshua"], ["god", "moses", "joshua"], ["moses"]]'::jsonb, ARRAY['moses', 'god', 'joshua']::text[], '[{"book": "신", "from": "31:1", "to": "31:29"}]'::jsonb, -1406, -1406, 'approx', 23, 'lm_exo_plains_moab', 'published'),
    ('era_divided_kingdom', '예루살렘 포위: 왕의 몰락', '포위는 길어지고, 마지막 순간 왕과 도시는 무너진다.', '["예루살렘 왕궁 안에서 시드기야가 여호와를 배반하고 작은 우상들을 궁전에 들여놓으며, 백성들이 그 우상들 앞에 엎드려 섬기는 모습", "바벨론 군대가 시드기야가 있는 예루살렘 성을 사방에서 둘러싸고 토성을 쌓아 공격하며, 성벽 위 사람들은 두려워하고 시드기야는 성 안에서 절망하는 장면", "시드기야가 바벨론 군사들에게 붙잡혀 눈에 어두운 안대를 하고 사슬에 묶인 채 바벨론으로 끌려가는 장면. 피와 상처는 직접 보이지 않는다"]'::jsonb, '[["zedekiah"], [], ["zedekiah"]]'::jsonb, ARRAY['zedekiah']::text[], '[{"book": "왕하", "from": "24:18", "to": "25:7"}]'::jsonb, -588, -586, 'approx', 23, 'lm_div_jerusalem', 'published'),
    ('era_nt_apostolic', '3차 선교(3): 헬라(고린도)—머무름과 결심', '바울은 헬라에서 머물며 다음 행선과 위험을 준비한다.', '["바울은 헬라에 머물며 사역을 이어 간다", "그는 시간을 보내며 다음 길을 준비한다", "위험의 기척 속에서도 바울의 결심은 더 분명해진다", "바울은 다음 여정을 향해 길을 다시 정한다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "20:2", "to": "20:3"}]'::jsonb, 56, 57, 'approx', 24, 'lm_nt_ap_corinth', 'published'),
    ('era_monarchy', '다윗의 마지막 명령: 나라를 굳게 하다', '다윗은 마지막으로 솔로몬에게 하나님을 따르라고 당부하고, 솔로몬은 흔들리는 왕권을 바로 세운다.', '["늙은 다윗 왕이 침상에 누워 젊은 솔로몬에게 마지막으로 당부하고, 큰 글자 없는 말풍선 안에는 솔로몬이 하나님만 따르고 율법의 길을 지키면 왕국이 견고해지는 상징 그림이 담겨 있다. 솔로몬은 무겁게 고개를 끄덕인다", "늙은 밧세바가 솔로몬 왕에게 와서 아도니야에게 수넴 여자 아비삭을 아내로 주라고 부탁하고, 큰 글자 없는 말풍선 안에는 아도니야와 아비삭이 함께 서 있는 그림이 담겨 있다. 솔로몬은 왕좌에서 화가 난 표정으로 단호하게 거절한다", "솔로몬이 군사 지휘관에게 명령을 내리고, 먼 배경에서는 아도니야가 심판받는 장면이 처리된다. 직접적인 칼질, 피, 상처, 시신은 보이지 않고, 솔로몬의 단호한 왕권 확립이 강조된다", "솔로몬이 브나야와 사독 같은 올바른 신하들을 세워 나라를 단단히 정비하고, 궁정 관리들이 질서 있게 서며 이스라엘 왕국이 안정되는 장면"]'::jsonb, '[["david", "solomon"], ["solomon"], ["solomon"], ["solomon"]]'::jsonb, ARRAY['david', 'solomon']::text[], '[{"book": "왕상", "from": "2:1", "to": "2:46"}]'::jsonb, -970, -970, 'approx', 24, 'lm_mon_jerusalem', 'published'),
    ('era_exodus', '모세의 마지막: 느보산과 축복', '모세는 느보산에서 약속의 땅을 바라보고 지파들을 축복한 뒤, 하나님 앞에서 사명을 마친다.', '["느보산 정상에서 120세의 모세가 가나안 땅을 바라보며 하나님의 말씀을 듣고, 멀리 요단과 약속의 땅이 펼쳐져 있다", "120세의 모세가 이스라엘 각 지파 대표들을 축복하고, 백성들은 지파별 무리로 조용히 서 있다", "120세의 흰 머리 모세가 기력이 쇠하지 않은 채로 여호수아에게 안수하고, 여호수아는 겸손히 고개를 숙인다", "모압 땅 벧브올 맞은편 골짜기, 모세의 무덤은 보이지 않는다. 앞쪽에는 모세가 쓰던 지팡이와 겉옷이 빈자리처럼 놓여 있고, 여호수아와 장로들과 백성들이 그 앞에 무릎 꿇고 얼굴을 가리며 통곡한다. 멀리 느보산 능선에는 모세가 마지막으로 서 있던 듯한 따뜻한 빛만 남아 있어, 백성이 모세의 죽음을 애도하는 장면임이 분명하다"]'::jsonb, '[["god", "moses"], ["moses"], ["moses", "joshua"], ["joshua"]]'::jsonb, ARRAY['moses', 'god', 'joshua']::text[], '[{"book": "신", "from": "32:48", "to": "34:12"}]'::jsonb, -1406, -1406, 'approx', 24, 'lm_exo_mt_nebo', 'published'),
    ('era_patriarch', '요셉의 꿈: 형제들의 시기', '요셉의 꿈과 편애가 형제들의 마음을 뒤틀리게 한다.', '["17세 안팎의 어린 요셉이 채색옷을 입고 형들 사이를 지나가자 미묘한 거리감이 흐른다", "17세 안팎의 어린 요셉이 채색옷을 입고 꿈을 이야기하자 형들의 표정이 굳는다. 꿈 이야기에는 곡식단 하나가 가운데 있고 주변에 다른 곡식단들이 중앙 곡식단에게 절하고 있는 모습이 나온다", "늙어서 머리가 하얀 야곱이 17세 안팎의 어린 요셉을 꾸짖지만 마음속에는 그 말을 담아둔다"]'::jsonb, '[["joseph"], ["joseph"], ["jacob", "joseph"]]'::jsonb, ARRAY['joseph', 'jacob', 'reuben', 'simeon', 'levi', 'judah', 'naphtali', 'gad', 'asher', 'issachar', 'zebulun', 'benjamin']::text[], '[{"book": "창", "from": "37:1", "to": "37:11"}]'::jsonb, -1915, -1915, 'approx', 24, 'lm_pat_hebron', 'published'),
    ('era_nt_public_ministry', '체포: 배신의 입맞춤', '유다의 배신으로 예수님이 체포되고 제자들은 흩어진다.', '["유다가 무리를 이끌고 밤길로 들어온다", "유다가 예수께 다가와 입맞춤으로 신호를 보낸다", "제자들은 소란 속에 당황하고 저항하려 한다", "예수는 붙잡혀 끌려가고 제자들은 흩어진다"]'::jsonb, '[["judas"], ["judas", "jesus"], ["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'judas', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot']::text[], '[{"book": "막", "from": "14:43", "to": "14:52"}, {"book": "마", "from": "26:47", "to": "26:56"}, {"book": "눅", "from": "22:47", "to": "22:53"}, {"book": "요", "from": "18:1", "to": "18:11"}]'::jsonb, 33, 33, 'approx', 24, 'lm_nt_pm_gethsemane', 'published'),
    ('era_nt_apostolic', '3차 선교(4): 밀레도—에베소 장로들과 작별', '바울은 장로들을 불러 눈물로 권면하고 다시는 못 볼지도 모른다고 말한다.', '["밀레도에 모인 장로들 앞에 바울이 선다", "바울은 지난 사역을 돌아보며 마지막 권면을 전한다", "그는 다시는 서로 얼굴을 보지 못할 수 있다고 말한다", "모두가 울며 작별하고 바울은 배에 오른다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "20:17", "to": "20:38"}]'::jsonb, 57, 57, 'approx', 25, 'lm_nt_ap_miletus', 'published'),
    ('era_exodus', '라합과 두 정탐꾼: 붉은 줄', '여리고 성 안에서 라합은 두 정탐꾼을 숨기고, 붉은 줄로 구원의 표를 매단다.', '["여호수아가 이스라엘 진영에서 두 정탐꾼을 여리고로 보내고, 두 사람은 조용히 길을 떠난다", "여리고 성 안 라합의 집 안, 라합은 모래색 머릿수건으로 검은 머리를 감싸고 청록색 겉옷과 갈색 어깨숄을 두른 같은 여인이며 오른쪽 뺨 아래 작은 점이 보인다. 그녀가 두 정탐꾼과 조심스럽게 대화한다. 방 안에는 붉은 실이나 붉은 줄이 전혀 보이지 않는다", "라합의 집 지붕 위, 같은 라합이 모래색 머릿수건과 청록색 겉옷과 갈색 어깨숄을 입고 오른쪽 뺨 아래 작은 점이 보이는 모습으로 군사들에게 성문 밖 방향을 손가락질한다. 뒤쪽 삼대 더미 속에는 같은 두 정탐꾼이 숨어 있다", "같은 라합이 모래색 머릿수건과 청록색 겉옷과 갈색 어깨숄을 입고 오른쪽 뺨 아래 작은 점이 보이는 모습으로 여리고 성벽 집 창문 밖에 붉은 줄을 매어 놓는다. 아래로 성벽과 길이 보인다"]'::jsonb, '[["joshua"], [], [], []]'::jsonb, ARRAY['god', 'joshua']::text[], '[{"book": "수", "from": "2:1", "to": "2:24"}]'::jsonb, -1406, -1406, 'approx', 25, 'lm_jud_jericho', 'published'),
    ('era_monarchy', '솔로몬의 지혜: 참 어머니를 가리다', '솔로몬은 하나님께 지혜를 구하고, 어려운 재판으로 그 지혜를 온 이스라엘 앞에 드러낸다.', '["밤의 꿈속, 솔로몬이 하나님 앞에 겸손히 무릎 꿇고 백성을 재판할 지혜를 구하며, 사람 형상 없는 하나님의 밝은 빛은 솔로몬의 구함을 기뻐하는 듯 따뜻하게 비추는 장면", "예루살렘 왕궁 재판 자리, 서로 다른 옷차림의 두 여자가 같은 아기를 두고 서로 자기 아이라고 주장하며 솔로몬 앞에 서 있고, 솔로몬은 집중해서 듣는 장면. 아기는 포대기에 싸여 안전하게 보인다", "솔로몬이 두 여자와 포대기에 싸인 아기를 앞에 두고 신하에게 칼을 가져오라고 단호하게 명령하자, 한 여자는 아기를 살려 달라는 듯 놀라 울고 다른 여자는 차갑게 굳어 있는 장면. 칼은 신하 손에만 보이고 아기에게 닿지 않는다", "솔로몬이 울며 아기를 살려 달라 한 여자가 참 어머니라고 판결하고 아기를 그 여자에게 돌려주며, 옆의 다른 여자는 속마음이 들켜 놀라 굳어 있는 장면. 궁정 사람들은 솔로몬의 지혜에 경외하는 표정이다"]'::jsonb, '[["solomon", "god"], ["solomon"], ["solomon"], ["solomon"]]'::jsonb, ARRAY['solomon', 'god']::text[], '[{"book": "왕상", "from": "3:1", "to": "3:28"}]'::jsonb, -967, -967, 'approx', 25, 'lm_mon_jerusalem', 'published'),
    ('era_patriarch', '요셉이 팔리다: 구덩이와 은', '시기는 요셉을 구덩이에 던지고 끝내 종으로 팔아넘긴다.', '["17세 안팎의 어린 요셉이 멀리서 오자 형들이 모여 속삭인다", "17세 안팎의 어린 요셉의 옷을 빼앗고 구덩이에 던지자 절규가 메아리친다", "17세 안팎의 어린 요셉은 구덩이에 있고, 유다가 다른 형들을 말리며 손을 뻗어 제지한다", "형들의 손에 은이 쥐어지고 멀리서는 17세 안팎의 어린 요셉이 상인들에게 끌려가듯 팔려간다"]'::jsonb, '[["joseph"], ["joseph"], ["joseph", "judah"], ["joseph"]]'::jsonb, ARRAY['joseph', 'judah']::text[], '[{"book": "창", "from": "37:12", "to": "37:36"}]'::jsonb, -1915, -1915, 'approx', 25, 'lm_pat_dothan', 'published'),
    ('era_nt_public_ministry', '재판: 빌라도 앞', '예수님은 불의한 재판을 받으시고 침묵 속에서 길을 걸으신다.', '["예수는 빌라도 앞에 서고 지도자들은 고발을 이어 간다", "빌라도는 예수에게 여러 가지를 묻지만 예수는 잠잠히 계신다", "지도자들은 더 강하게 몰아붙이고 빌라도는 흔들린다", "끝내 판결이 내려지고 예수는 십자가의 길로 넘겨진다"]'::jsonb, '[["jesus", "pilate"], ["jesus", "pilate"], ["pilate"], ["jesus", "pilate"]]'::jsonb, ARRAY['jesus', 'pilate']::text[], '[{"book": "막", "from": "15:1", "to": "15:15"}, {"book": "마", "from": "27:11", "to": "27:26"}, {"book": "눅", "from": "23:1", "to": "23:25"}, {"book": "요", "from": "18:28", "to": "19:16"}]'::jsonb, 33, 33, 'approx', 25, 'lm_nt_pm_jerusalem', 'published'),
    ('era_nt_apostolic', '로마행(1): 예루살렘 체포', '성전 소동으로 바울이 붙잡히며 ‘로마까지’의 여정이 시작된다.', '["예루살렘 성전에서 바울을 둘러싼 소동이 일어난다", "군중은 바울을 붙잡고 거세게 몰아붙인다", "병사들이 바울을 계단 위로 데려가며 상황을 수습한다", "묶인 바울 앞에 로마로 이어질 긴 여정이 시작된다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "21:27", "to": "21:36"}]'::jsonb, 57, 57, 'approx', 26, 'lm_nt_ap_jerusalem', 'published'),
    ('era_patriarch', '보디발의 집: 성실과 누명', '요셉은 유혹을 거절하지만 누명을 쓰고 감옥으로 내려간다.', '["종으로 팔려 온 요셉이 보디발의 집 살림을 정리하며 보디발에게 신뢰를 얻고 열쇠를 넘겨받는다", "이집트 저택의 방 안, 화려한 침상 가장자리에 앉은 여인이 종 요셉을 향해 손짓하고, 요셉은 문가 앞에 서서 몸을 뒤로 물리며 두 손을 가슴 앞에 들어 단호히 거절하는 표정", "여자가 요셉의 옷을 붙잡아 찢어지고, 옷을 남기고 달아나는 종 요셉의 모습", "감옥에 갇힌 종 요셉이 죄수들의 일을 맡아 분주히 정리한다"]'::jsonb, '[["potiphar", "joseph"], ["joseph"], ["joseph"], ["joseph"]]'::jsonb, ARRAY['joseph', 'potiphar']::text[], '[{"book": "창", "from": "39:1", "to": "39:23"}]'::jsonb, -1910, -1909, 'approx', 26, 'lm_pat_unknown', 'published'),
    ('era_monarchy', '성전 건축: 손으로 짓는 집', '솔로몬은 오랜 준비 끝에 성전을 건축한다.', '["솔로몬이 두로 왕 히람에게 성전 건축에 쓸 백향목과 잣나무 재목을 제공해 달라고 요청하고, 히람이 기뻐하며 재목을 보내 주기로 하는 장면", "예루살렘 성전 터에서 솔로몬의 건축자들과 히람의 건축자들이 함께 돌과 목재로 성전을 열심히 건축하고, 솔로몬이 현장을 바라보며 기뻐하는 장면", "으리으리한 성전이 완성되어 금빛 장식과 높은 기둥이 빛나고, 솔로몬이 성전 앞에서 기뻐하며 하나님께 감사하는 장면"]'::jsonb, '[["solomon"], ["solomon"], ["solomon"]]'::jsonb, ARRAY['solomon']::text[], '[{"book": "왕상", "from": "5:1", "to": "6:38"}]'::jsonb, -966, -959, 'approx', 26, 'lm_mon_jerusalem', 'published'),
    ('era_nt_public_ministry', '십자가: 끝까지 사랑', '예수님은 십자가에서 마지막까지 사랑을 드러내신다.', '["예수는 골고다로 향하는 길을 걸어가신다", "십자가가 세워지고 사람들은 멀리서 지켜본다", "예수는 마지막 말씀을 남기신다", "예수의 죽음 앞에 사람들이 깊은 충격에 잠긴다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "막", "from": "15:21", "to": "15:39"}, {"book": "마", "from": "27:32", "to": "27:54"}, {"book": "눅", "from": "23:26", "to": "23:49"}, {"book": "요", "from": "19:17", "to": "19:37"}]'::jsonb, 33, 33, 'approx', 26, 'lm_nt_pm_golgotha', 'published'),
    ('era_exodus', '요단강 도하: 물이 멈추다', '이스라엘은 요단강을 건너며 약속의 땅에 들어선다.', '["여호수아가 시켜 제사장들이 언약궤를 메고 요단강 앞에 선다", "여호수아가 뒤에서 보고있고, 제사장들의 발이 물을 밟자 요단강 물이 갈라진다", "이스라엘 백성이 마른 땅으로 요단강을 건너간다", "여호수아가 시켜 열두 사람이 제사장들의 발이 섰던 곳에 돌을 세운다"]'::jsonb, '[["joshua"], ["joshua"], ["joshua"], ["joshua"]]'::jsonb, ARRAY['joshua']::text[], '[{"book": "수", "from": "3:1", "to": "4:24"}]'::jsonb, -1406, -1406, 'approx', 26, 'lm_jud_jericho', 'published'),
    ('era_nt_apostolic', '로마행(2): 가이사랴 재판과 상소', '바울은 재판 자리에서 증언하고 ‘가이사에게 상소’한다.', '["가이사랴 재판정에 바울이 다시 선다", "총독들과 왕 앞에서 바울은 자신의 믿음을 증언한다", "논의가 이어지지만 바울은 흔들리지 않는다", "바울은 끝내 가이사에게 상소한다"]'::jsonb, '[["paul", "festus", "agrippa"], ["paul", "festus", "agrippa"], ["paul", "festus", "agrippa"], ["paul", "festus"]]'::jsonb, ARRAY['paul', 'festus', 'agrippa']::text[], '[{"book": "행", "from": "24:10", "to": "24:27"}, {"book": "행", "from": "25:7", "to": "25:12"}, {"book": "행", "from": "26:1", "to": "26:32"}]'::jsonb, 59, 59, 'approx', 27, 'lm_nt_ap_caesarea_maritima', 'published'),
    ('era_patriarch', '바로의 꿈: 총리 요셉', '바로의 꿈을 해석한 요셉은 애굽의 총리로 세워진다.', '["바로가 꿈에서 깨어 불안해하고 신하들이 술렁인다", "종 요셉이 바로 앞에서 일곱 해 풍년과 일곱 해 흉년을 설명하며 계획을 제시한다", "요셉은 애굽의 총리로서 절제된 흰 세마포 옷과 금 장식을 하고 수 많은 애굽 사람들 앞에 선다"]'::jsonb, '[["pharaoh"], ["pharaoh", "joseph"], ["joseph"]]'::jsonb, ARRAY['joseph', 'pharaoh']::text[], '[{"book": "창", "from": "41:1", "to": "41:57"}]'::jsonb, -1900, -1900, 'approx', 27, 'lm_pat_unknown', 'published'),
    ('era_nt_public_ministry', '부활과 승천: 새 시작', '부활하신 예수님은 제자들에게 사명을 주시고 승천하신다.', '["새벽에 여인들이 빈 무덤 앞에 선다", "부활하신 예수는 여인들과 제자들에게 나타나신다", "예수는 제자들에게 사명을 맡기신다", "예수는 감람산에서 승천하시고 제자들은 하늘을 바라본다"]'::jsonb, '[["mary_magdalene"], ["jesus", "mary_magdalene"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'mary_magdalene', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "28:1", "to": "28:20"}, {"book": "눅", "from": "24:1", "to": "24:53"}, {"book": "요", "from": "20:1", "to": "20:29"}, {"book": "행", "from": "1:1", "to": "1:11"}]'::jsonb, 33, 33, 'approx', 27, 'lm_nt_pm_jerusalem', 'published')
)
insert into events (era_id, title, summary, story_scenes, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.story_scenes,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  story_scenes = excluded.story_scenes,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, story_scenes, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, landmark_code, status) as (
  values
    ('era_monarchy', '솔로몬: 이방의 경탄부터 타락까지', '솔로몬의 지혜와 영화는 이방을 놀라게 했지만, 말년의 타락은 왕국의 균열을 예고했다.', '["스바 여왕이 낙타 행렬과 많은 향품, 보석, 금을 가지고 예루살렘에 도착하고, 솔로몬이 궁정 앞에서 맞이하는 장면", "솔로몬의 성과 궁전 안에 금은보화와 귀한 그릇들이 가득 쌓여 있고, 솔로몬은 화려한 보좌 곁에서 부유한 왕국을 바라보는 장면", "솔로몬이 다른 나라 왕비들을 궁정으로 들이고, 그들이 가져온 작은 우상들이 성전과 궁전 주변에 조금씩 채워지는 장면", "금은보화와 우상들이 가득한 성전 안에 하나님의 거룩한 빛이 엄중하게 임하고, 큰 글자 없는 말풍선 안에는 성전과 왕국의 영광이 황폐해지는 경고 그림이 담긴 장면"]'::jsonb, '[["solomon"], ["solomon"], ["solomon"], ["god", "solomon"]]'::jsonb, ARRAY['solomon', 'god']::text[], '[{"book": "왕상", "from": "10:1", "to": "11:13"}]'::jsonb, -950, -950, 'approx', 27, 'lm_mon_jerusalem', 'published'),
    ('era_exodus', '여리고: 침묵의 행진', '상식을 깨는 순종의 행진 끝에 성벽이 무너진다.', '["하나님의 영광이 여호수아 앞에 임하고, 큰 글자 없는 말풍선 안에는 6일 동안 조용히 여리고 성을 돌다가 7일째 양뿔 나팔과 큰 함성으로 성벽이 무너지는 상징 그림이 담겨 있다", "여호수아와 양뿔 나팔을 든 제사장들, 언약궤를 멘 제사장들이 앞서고, 뒤에는 군사들이 여리고 성벽 주변을 침묵 속에 한 바퀴 도는 장면", "일곱째 날 여호수아의 신호에 맞춰 제사장들이 양뿔 나팔을 길게 불고 군사들이 여리고 성을 향해 크게 외치자, 여리고 성벽이 무너지는 장면", "무너진 여리고 성벽 사이로 여호수아와 군사들이 질서 있게 들어가 성을 점령하는 장면. 폭력이나 시신은 직접 보이지 않는다"]'::jsonb, '[["god", "joshua"], ["joshua"], ["joshua"], ["joshua"]]'::jsonb, ARRAY['god', 'joshua']::text[], '[{"book": "수", "from": "6:1", "to": "6:20"}]'::jsonb, -1406, -1406, 'approx', 27, 'lm_jud_jericho', 'published'),
    ('era_nt_apostolic', '로마행(3): 폭풍의 항해', '폭풍 속에서 바울은 ‘두려워 말라’는 약속으로 사람들을 붙든다.', '["거센 바람이 배를 뒤흔들고 사람들은 두려움에 빠진다", "오랜 폭풍 속에 모두가 지쳐 간다", "바울은 하나님이 살려 주실 것이라며 사람들을 붙든다", "배는 계속 흔들리지만 사람들은 다시 버틸 힘을 얻는다"]'::jsonb, '[[], [], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "27:13", "to": "27:26"}]'::jsonb, 59, 59, 'approx', 28, 'lm_nt_ap_crete', 'published'),
    ('era_exodus', '아간: 감춘 것이 드러나다', '숨긴 탐욕이 공동체의 패배로 드러나고, 정리가 시작된다.', '["여호수아가 아이 성 함락을 위해 군사 3000명을 올려보냈지만, 군사들이 패배하고 놀란 표정으로 이스라엘 진영에 돌아오는 모습", "여호수아가 하나님 앞에 엎드려 기도하고, 하나님의 영광에서 나온 큰 글자 없는 말풍선 안에는 이스라엘 가운데 범죄를 저지른 사람이 있어 제비를 뽑아 찾아내야 함을 상징하는 그림이 담겨 있다", "아간이 제비에서 뽑혀 떨며 서 있고, 그의 장막 앞에는 숨겨 두었던 은과 금이 드러나며, 여호수아가 불같이 화를 내는 장면"]'::jsonb, '[["joshua"], ["god", "joshua"], ["joshua", "achan"]]'::jsonb, ARRAY['god', 'joshua', 'achan']::text[], '[{"book": "수", "from": "7:1", "to": "7:26"}]'::jsonb, -1406, -1406, 'approx', 28, 'lm_jud_ai', 'published'),
    ('era_patriarch', '요셉의 정체 공개: 울음의 방', '요셉은 더 이상 참지 못하고 형제들에게 자신을 드러낸다.', '["파라오처럼 보이지 않는 애굽 총리 요셉이 형들 앞에서 울음을 터뜨리자 형들은 당황해 얼어붙는다", "요셉이 총리의 겉모습 일부를 내려놓고 자신이 요셉임을 밝히자 형들이 크게 놀란다", "파라오처럼 보이지 않는 총리 차림의 요셉이 베냐민을 끌어안고, 형들은 뒤에서 놀란 얼굴로 그 모습을 바라본다"]'::jsonb, '[["joseph"], ["joseph"], ["joseph", "benjamin"]]'::jsonb, ARRAY['joseph']::text[], '[{"book": "창", "from": "45:1", "to": "45:15"}]'::jsonb, -1885, -1885, 'approx', 28, 'lm_pat_egypt_court', 'published'),
    ('era_patriarch', '고센 정착: 만남과 눈물', '요셉은 야곱을 맞이하고, 이스라엘은 고센에 자리 잡는다.', '["고센 들판 길 위, 애굽 총리 요셉이 흰 세마포 겉옷과 얇은 금 목걸이를 단정히 하고 작은 전차를 타고 야곱의 가족을 맞으러 달려간다", "고센 들판 입구, 흰 세마포 옷과 얇은 금 목걸이를 한 애굽 총리 요셉이 낡은 여행복의 야곱을 두 팔로 끌어안고 눈물을 흘린다", "애굽 궁정 안, 왕관을 쓴 바로와 흰 수염의 야곱이 서로 마주 서 있고, 흰 세마포 옷과 얇은 금 목걸이를 한 총리 요셉은 두 사람 사이 옆쪽에서 조용히 안내한다"]'::jsonb, '[["joseph"], ["jacob", "joseph"], ["pharaoh", "jacob", "joseph"]]'::jsonb, ARRAY['jacob', 'joseph', 'pharaoh']::text[], '[{"book": "창", "from": "46:28", "to": "47:12"}]'::jsonb, -1880, -1879, 'approx', 29, 'lm_pat_goshen', 'published'),
    ('era_nt_apostolic', '로마행(4): 멜리데(몰타) 표류', '난파 후 섬에 도착하고, 바울을 통한 표징으로 사람들이 마음을 연다.', '["난파한 사람들이 멜리데 섬 해안에 간신히 오른다", "섬사람들은 비와 추위 속에서 불을 피워 맞아 준다", "바울이 독사에 물리고도 해를 입지 않자 섬사람들은 크게 놀란다", "바울이 병든 이들을 고치자 섬사람들은 일행을 존중하며 필요한 것을 채워 준다"]'::jsonb, '[["paul"], [], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "27:39", "to": "27:44"}, {"book": "행", "from": "28:1", "to": "28:10"}]'::jsonb, 60, 60, 'approx', 29, 'lm_nt_ap_malta', 'published'),
    ('era_exodus', '아이 성 정복: 다시 일어서다', '하나님은 실패 뒤 다시 길을 여시고, 이스라엘은 말씀대로 아이 성을 차지한 뒤 제단을 쌓는다.', '["하나님의 영광이 여호수아 앞에 임하고, 큰 글자 없는 말풍선 안에는 두려워하지 말고 아이 성을 차지하라는 하나님의 명령을 상징하는 그림이 담겨 있다", "여호수아와 이스라엘 군대가 하나님의 지시대로 아이 성을 차지하는 장면. 전투의 긴장감은 보이지만 폭력이나 시신은 직접 보이지 않는다", "여호수아와 군대가 돌로 제단을 쌓고 하나님께 번제와 화목제를 드리며 감사하는 장면"]'::jsonb, '[["god", "joshua"], ["joshua"], ["god", "joshua"]]'::jsonb, ARRAY['god', 'joshua']::text[], '[{"book": "수", "from": "8:1", "to": "8:35"}]'::jsonb, -1406, -1406, 'approx', 29, 'lm_jud_ai', 'published'),
    ('era_exodus', '기브온 전투: 해와 달이 머물다', '여호수아가 기브온을 돕는 전투에서 하나님은 우박과 긴 낮으로 승리를 이루신다.', '["아도니세덱과 헤브론, 야르뭇, 라기스, 에글론의 왕들이 지도와 성읍 모형을 가운데 두고 모여 여호수아를 칠 계획을 짜는 모습. 이름표나 글자는 보이지 않는다", "여호수아가 이스라엘 군대와 함께 전투에서 이기고, 하나님의 영광이 하늘에서 도망하는 군사들 쪽으로 큰 우박을 내리는 장면. 폭력이나 시신은 직접 보이지 않는다", "여호수아가 하늘을 향해 명령하듯 서 있고, 해와 달이 멈추어 해가 중천에서 하루 종일 떠 있는 장면"]'::jsonb, '[[], ["god", "joshua"], ["god", "joshua"]]'::jsonb, ARRAY['god', 'joshua']::text[], '[{"book": "수", "from": "10:1", "to": "10:15"}]'::jsonb, -1406, -1406, 'approx', 30, 'lm_exo_gibeon_battle', 'published'),
    ('era_nt_apostolic', '로마행(5): 로마 도착', '바울은 로마에 도착해 묶인 상태로도 복음을 전한다.', '["바울은 마침내 로마에 들어선다", "그는 묶인 몸이지만 머물 곳을 얻게 된다", "찾아오는 사람들에게 하나님 나라를 전한다", "복음은 로마 한가운데서도 막히지 않는다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "28:14", "to": "28:31"}]'::jsonb, 60, 62, 'approx', 30, 'lm_nt_ap_rome', 'published'),
    ('era_patriarch', '야곱의 축복: 열두 아들', '야곱은 마지막 순간 아들들을 불러 각 지파의 길을 예언적으로 선언한다.', '["침상 앞, 늙은 야곱이 팔을 어긋맞겨 오른손을 어린 에브라임의 머리에 얹고 왼손을 므낫세의 머리에 얹으며, 흰 세마포 옷과 얇은 금 목걸이를 한 총리 요셉은 놀란 얼굴로 야곱의 손을 조심히 바로잡으려 하지만 야곱은 맞다고 하는 장면", "넓은 애굽 집 안, 눈이 어둡고 늙은 야곱 앞에 열두 아들(흰 세마포 옷과 얇은 금 목걸이를 한 총리 요셉을 포함한 중년의 남자들)이 반원으로 둘러섰고 야곱이 한사람씩 축복하는 모습", "늙은 야곱이 침대에 발을 올려놓고 숨을 거두고, 열두 아들(흰 세마포 옷과 얇은 금 목걸이를 한 총리 요셉을 중년의 남자들)이 흐느낀다"]'::jsonb, '[["joseph", "jacob"], ["joseph", "jacob"], ["joseph", "jacob"]]'::jsonb, ARRAY['jacob', 'joseph']::text[], '[{"book": "창", "from": "48:1", "to": "48:22"}, {"book": "창", "from": "49:1", "to": "49:33"}]'::jsonb, -1860, -1860, 'approx', 30, 'lm_pat_unknown', 'published'),
    ('era_exodus', '여호수아의 마지막 권면: 언약을 붙들라', '늙은 여호수아는 백성에게 하나님만 섬기라고 당부하고, 언약의 증거를 세운 뒤 사명을 마친다.', '["늙은 흰 머리 여호수아가 장로들을 불러 하나님이 우리를 인도하셨음을 말하고, 큰 글자 없는 말풍선 안에는 전쟁의 승리와 제비 뽑아 땅을 나눈 그림이 담겨 있다", "늙은 흰 머리 여호수아가 백성 앞에서 절대 우상을 섬기거나 악한 일을 하면 안 된다고 말하고, 큰 글자 없는 말풍선 안에는 깨진 우상과 하나님께 돌아서는 백성의 상징 그림이 담겨 있다", "늙은 흰 머리 여호수아가 하나님의 행하심이 적힌 율법책을 기록하고, 큰 돌을 가져다가 성소 근처 상수리나무 아래 세워 놓는 장면", "늙은 여호수아가 침상에서 조용히 생을 마치고, 백성들이 침상 곁과 장막 밖에서 슬퍼하며 애도하는 장면"]'::jsonb, '[["joshua"], ["joshua"], ["god", "joshua"], ["joshua"]]'::jsonb, ARRAY['god', 'joshua']::text[], '[{"book": "수", "from": "23:1", "to": "24:30"}]'::jsonb, -1390, -1390, 'approx', 31, 'lm_exo_shechem_oak', 'published')
)
insert into events (era_id, title, summary, story_scenes, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.story_scenes,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  story_scenes = excluded.story_scenes,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;


alter table events enable trigger trg_notify_on_new_event;
commit;
